(156, 'theme_mods_LeSys-theme', 'a:49:{i:0;b:0;s:18:\"nav_menu_locations\";a:4:{s:12:\"primary-menu\";i:2;s:16:\"footer-platforms\";i:18;s:19:\"footer-capabilities\";i:20;s:14:\"footer-company\";i:19;}s:18:\"custom_css_post_id\";i:-1;s:16:\"sidebars_widgets\";a:2:{s:4:\"time\";i:1781721024;s:4:\"data\";a:1:{s:19:\"wp_inactive_widgets\";a:5:{i:0;s:7:\"block-2\";i:1;s:7:\"block-3\";i:2;s:7:\"block-4\";i:3;s:7:\"block-5\";i:4;s:7:\"block-6\";}}}s:20:\"global_title_setting\";s:12:\"Get in Touch\";s:23:\"global_heading1_setting\";s:19:\"Talk to One of Our \";s:23:\"global_heading2_setting\";s:9:\"Experts. \";s:24:\"global_paragraph_setting\";s:152:\"Every request routes to a dedicated solution owner. You\'ll get a tailored walkthrough, a solution brief and a booking link — within one business day. \";s:14:\"feature_1_icon\";s:34:\"<i class=\"fa-solid fa-check\"></i> \";s:15:\"feature_1_title\";s:20:\"Mapped to your goal \";s:14:\"feature_1_desc\";s:61:\"We map your challenge to the exact platforms before we meet. \";s:14:\"feature_2_icon\";s:40:\"<i class=\"fa-regular fa-calendar\"></i>  \";s:15:\"feature_2_title\";s:26:\"Calendar booking included \";s:14:\"feature_2_desc\";s:60:\"Pick a time on the confirmation page — no back-and-forth. \";s:15:\"feature_3_title\";s:26:\"Defense-grade & compliant \";s:14:\"feature_3_desc\";s:49:\"NCA ECC 2.0 · SDAIA PDPL · ISO 27001 · SOC 2. \";s:14:\"feature_3_icon\";s:42:\"<i class=\"fa-solid fa-shield-halved\"></i> \";s:22:\"chosen_contact_form_id\";i:140;s:20:\"lesys_social_twitter\";s:23:\"https://leadergroup.com\";s:22:\"lesys_social_instagram\";s:23:\"https://leadergroup.com\";s:21:\"lesys_social_linkedin\";s:23:\"https://leadergroup.com\";s:15:\"success_heading\";s:22:\"Customer Success Story\";s:14:\"success_title1\";s:28:\"Entire Cities, Operated From\";s:14:\"success_title2\";s:14:\"Command Center\";s:22:\"success_column_1_title\";s:9:\"Challenge\";s:22:\"success_column_2_title\";s:8:\"Solution\";s:26:\"success_column_1_paragraph\";s:116:\"Waste, lighting and field services ran across disconnected systems no real-time visibility, no proof of performance.\";s:26:\"success_column_2_paragraph\";s:106:\"Caguar, LightSense, Visual and Discretal unified under one City Operations Center, operated 24/7 by LeSys.\";s:22:\"success_column_3_title\";s:6:\"Result\";s:17:\"story_button_text\";s:17:\"Talk to an Expert\";s:16:\"story_button_url\";s:8:\"#contact\";s:26:\"success_column_3_paragraph\";s:99:\"70% energy saved, 18% lower fleet fuel, 25% fewer missed collections and sub-5-second SOS response.\";s:14:\"success_title3\";s:8:\"a Single\";s:13:\"trusted_title\";s:19:\"Trusted Foundations\";s:16:\"trusted_subtitle\";s:100:\"Strategic technology alliances, verified Saudi presence, and compliance engineered into every layer.\";s:11:\"logo_1_name\";s:5:\"CISCO\";s:10:\"logo_1_css\";s:8:\"lg-cisco\";s:11:\"logo_2_name\";s:4:\"DELL\";s:10:\"logo_2_css\";s:7:\"lg-dell\";s:11:\"logo_3_name\";s:5:\"aruba\";s:10:\"logo_3_css\";s:8:\"lg-aruba\";s:11:\"logo_5_name\";s:19:\"▲ Microsoft Azure\";s:10:\"logo_5_css\";s:8:\"lg-azure\";s:11:\"logo_6_name\";s:3:\"aws\";s:10:\"logo_6_css\";s:6:\"lg-aws\";s:11:\"logo_7_name\";s:9:\"FÜRTINET\";s:10:\"logo_7_css\";s:11:\"lg-fortinet\";s:11:\"logo_8_name\";s:8:\"Otenable\";s:10:\"logo_8_css\";s:10:\"lg-tenable\";}', 'on'),
