(1982, '_transient_mp_pt_api_products', 'a:1:{s:8:\"products\";a:53:{i:0;a:62:{s:5:\"title\";s:37:\"Job Applications Import/Export Add-on\";s:2:\"id\";i:68046;s:10:\"created_at\";s:20:\"2026-01-07T18:08:03Z\";s:10:\"updated_at\";s:20:\"2026-04-16T14:47:21Z\";s:4:\"type\";s:8:\"variable\";s:6:\"status\";s:7:\"publish\";s:12:\"downloadable\";b:0;s:7:\"virtual\";b:0;s:9:\"permalink\";s:77:\"https://market.presstigers.com/product/job-applications-import-export-add-on/\";s:3:\"sku\";s:0:\"\";s:5:\"price\";s:2:\"15\";s:13:\"regular_price\";s:0:\"\";s:10:\"sale_price\";N;s:10:\"price_html\";s:417:\"<span class=\"woocommerce-Price-amount amount\" aria-hidden=\"true\"><bdi><span class=\"woocommerce-Price-currencySymbol\">&#36;</span>15.00</bdi></span> <span aria-hidden=\"true\">&ndash;</span> <span class=\"woocommerce-Price-amount amount\" aria-hidden=\"true\"><bdi><span class=\"woocommerce-Price-currencySymbol\">&#36;</span>49.00</bdi></span><span class=\"screen-reader-text\">Price range: &#36;15.00 through &#36;49.00</span>\";s:7:\"taxable\";b:0;s:10:\"tax_status\";s:7:\"taxable\";s:9:\"tax_class\";s:0:\"\";s:14:\"managing_stock\";b:0;s:14:\"stock_quantity\";N;s:8:\"in_stock\";b:1;s:18:\"backorders_allowed\";b:0;s:11:\"backordered\";b:0;s:17:\"sold_individually\";b:1;s:12:\"purchaseable\";b:1;s:8:\"featured\";b:0;s:7:\"visible\";b:1;s:18:\"catalog_visibility\";s:7:\"visible\";s:7:\"on_sale\";b:0;s:11:\"product_url\";s:0:\"\";s:11:\"button_text\";s:0:\"\";s:6:\"weight\";N;s:10:\"dimensions\";a:4:{s:6:\"length\";s:0:\"\";s:5:\"width\";s:0:\"\";s:6:\"height\";s:0:\"\";s:4:\"unit\";s:2:\"in\";}s:17:\"shipping_required\";b:1;s:16:\"shipping_taxable\";b:1;s:14:\"shipping_class\";s:0:\"\";s:17:\"shipping_class_id\";N;s:11:\"description\";s:642:\"<p>The <strong>Job Applications Import/Export Add-on</strong> is a powerful extension for Simple Job Board that allows you to safely export and import job applications (matching with job titles) along with applicant resumes and attachments between WordPress websites — directly from the admin panel.</p>\n<p><strong>System Requirements</strong></p>\n<ul>\n<li>WordPress 6.0 or higher (6.2+ recommended)</li>\n<li>PHP 7.4 or higher (PHP 8.0+ recommended)</li>\n<li>PHP ZIP extension enabled</li>\n<li>PHP mbstring extension enabled</li>\n<li>Write access to:\n<ul>\n<li>wp-content/uploads/</li>\n<li>wp-content/uploads/jobpost/</li>\n</ul>\n</li>\n</ul>\n\";s:17:\"short_description\";s:75:\"<p>Export and Import job applications along resumes &amp; attachments.</p>\n\";s:15:\"reviews_allowed\";b:1;s:14:\"average_rating\";s:4:\"0.00\";s:12:\"rating_count\";i:0;s:11:\"related_ids\";a:5:{i:0;i:160;i:1;i:27020;i:2;i:8401;i:3;i:27407;i:4;i:157;}s:10:\"upsell_ids\";a:0:{}s:14:\"cross_sell_ids\";a:0:{}s:9:\"parent_id\";i:0;s:10:\"categories\";a:1:{i:0;s:16:\"Simple Job Board\";}s:4:\"tags\";a:0:{}s:6:\"images\";a:1:{i:0;a:7:{s:2:\"id\";i:68063;s:10:\"created_at\";s:20:\"2026-01-07T19:33:40Z\";s:10:\"updated_at\";s:20:\"2026-01-07T19:33:40Z\";s:3:\"src\";s:99:\"https://market.presstigers.com/wp-content/uploads/2026/01/job-applications-import-export-add-on.jpg\";s:5:\"title\";s:37:\"job applications import export add-on\";s:3:\"alt\";s:0:\"\";s:8:\"position\";i:0;}}s:12:\"featured_src\";s:99:\"https://market.presstigers.com/wp-content/uploads/2026/01/job-applications-import-export-add-on.jpg\";s:10:\"attributes\";a:1:{i:0;a:6:{s:4:\"name\";s:7:\"License\";s:4:\"slug\";s:7:\"license\";s:8:\"position\";i:0;s:7:\"visible\";b:1;s:9:\"variation\";b:1;s:7:\"options\";a:2:{i:0;s:7:\"Regular\";i:1;s:8:\"Extended\";}}}s:9:\"downloads\";a:0:{}s:14:\"download_limit\";i:-1;s:15:\"download_expiry\";i:-1;s:13:\"download_type\";s:8:\"standard\";s:13:\"purchase_note\";s:0:\"\";s:11:\"total_sales\";s:1:\"0\";s:10:\"variations\";a:2:{i:0;a:30:{s:2:\"id\";i:68049;s:10:\"created_at\";s:20:\"2026-01-07T19:08:25Z\";s:10:\"updated_at\";s:20:\"2026-01-07T19:20:17Z\";s:12:\"downloadable\";b:1;s:7:\"virtual\";b:1;s:9:\"permalink\";s:103:\"http