:\"2023-07-05T13:35:16Z\";s:10:\"updated_at\";s:20:\"2023-07-05T13:35:21Z\";s:3:\"src\";s:100:\"https://market.presstigers.com/wp-content/uploads/2020/07/Frontend-Job-Posting-PaidListingAdd-on.jpg\";s:5:\"title\";s:38:\"Frontend-Job-Posting-PaidListingAdd-on\";s:3:\"alt\";s:49:\"Frontend Job Posting Add-on with Paid Job Listing\";s:8:\"position\";i:0;}}s:10:\"attributes\";a:1:{i:0;a:3:{s:4:\"name\";s:7:\"License\";s:4:\"slug\";s:7:\"license\";s:6:\"option\";s:8:\"Extended\";}}s:9:\"downloads\";a:1:{i:0;a:3:{s:2:\"id\";s:36:\"ea290b43-172c-403a-9142-ccbf0a034f1e\";s:4:\"name\";s:27:\"SJB Frontend Jobpost Add-on\";s:4:\"file\";s:113:\"https://market.presstigers.com/wp-content/uploads/woocommerce_uploads/2020/07/frontend-job-post-1.7.11-uimfa5.zip\";}}s:14:\"download_limit\";i:-1;s:15:\"download_expiry\";i:365;}}s:6:\"parent\";a:0:{}s:16:\"grouped_products\";a:0:{}s:10:\"menu_order\";i:3;s:14:\"add_on_version\";s:6:\"1.7.11\";s:16:\"plugin_main_slug\";s:39:\"frontend-job-post/frontend-job-post.php\";}i:3;a:62:{s:5:\"title\";s:27:\"Mobile App Connector Add-on\";s:2:\"id\";i:56022;s:10:\"created_at\";s:20:\"2023-02-22T06:40:43Z\";s:10:\"updated_at\";s:20:\"2025-04-15T11:50:22Z\";s:4:\"type\";s:8:\"variable\";s:6:\"status\";s:7:\"publish\";s:12:\"downloadable\";b:0;s:7:\"virtual\";b:0;s:9:\"permalink\";s:67:\"https://market.presstigers.com/product/mobile-app-connector-add-on/\";s:3:\"sku\";s:0:\"\";s:5:\"price\";s:2:\"49\";s:13:\"regular_price\";s:0:\"\";s:10:\"sale_price\";N;s:10:\"price_html\";s:419:\"<span class=\"woocommerce-Price-amount amount\" aria-hidden=\"true\"><bdi><span class=\"woocommerce-Price-currencySymbol\">&#36;</span>49.00</bdi></span> <span aria-hidden=\"true\">&ndash;</span> <span class=\"woocommerce-Price-amount amount\" aria-hidden=\"true\"><bdi><span class=\"woocommerce-Price-currencySymbol\">&#36;</span>149.00</bdi></span><span class=\"screen-reader-text\">Price range: &#36;49.00 through &#36;149.00</span>\";s:7:\"taxable\";b:0;s:10:\"tax_status\";s:7:\"taxable\";s:9:\"tax_class\";s:0:\"\";s:14:\"managing_stock\";b:0;s:14:\"stock_quantity\";N;s:8:\"in_stock\";b:1;s:18:\"backorders_allowed\";b:0;s:11:\"backordered\";b:0;s:17:\"sold_individually\";b:1;s:12:\"purchaseable\";b:1;s:8:\"featured\";b:0;s:7:\"visible\";b:1;s:18:\"catalog_visibility\";s:7:\"visible\";s:7:\"on_sale\";b:0;s:11:\"product_url\";s:0:\"\";s:11:\"button_text\";s:0:\"\";s:6:\"weight\";N;s:10:\"dimensions\";a:4:{s:6:\"length\";s:0:\"\";s:5:\"width\";s:0:\"\";s:6:\"height\";s:0:\"\";s:4:\"unit\";s:2:\"in\";}s:17:\"shipping_required\";b:1;s:16:\"shipping_taxable\";b:1;s:14:\"shipping_class\";s:0:\"\";s:17:\"shipping_class_id\";N;s:11:\"description\";s:6069:\"<p>Mobile App API Connector is an add-on by <a href=\"https://presstigers.com\">PressTigers</a> that can help you extend the reach of your <a href=\"https://wordpress.org/plugins/simple-job-board/\">Simple Job Board</a> plugin with a mobile app, allowing the site administrator to create and browse jobs directly from their mobile devices.</p>\n<p>The connector retrieves job listings, settings, applicant details, and other data stored in the Simple Job Board plugin from your website to display it in the mobile app. It is a convenient way to manage your job board and give your business a competitive advantage in the job market.</p>\n<p>Please visit the <a href=\"https://market.presstigers.com/wp-content/uploads/2023/02/Connect-Mobile-App-with-Job-Board-Website.pdf\" target=\"_blank\" rel=\"noopener\">instruction guide</a> to configure the Mobile App Connector Add-on with the mobile app.</p>\n<div class=\"col-md-12\">\n<div class=\"row\"><a href=\"https://play.google.com/store/apps/details?id=com.nextbridge.simple_job_board&amp;pcampaignid=pcampaignidMKT-Other-global-all-co-prtnr-py-PartBadge-Mar2515-1\" target=\"_blank\" rel=\"noopener\"><img class=\"\" src=\"https://play.google.com/intl/en_us/badges/static/images/badges/en_badge_web_generic.png\" alt=\"Get it on Google Play\" width=\"200\" height=\"89\" /></a><a href=\"https://apps.apple.com/us/app/simple-job-board/id1671815165\" target=\"_blank\" rel=\"noopener\"><img src=\"https://tools.applemediaservices.com/api/badges/download-on-the-app-store/black/en-us?size=250x83&amp;releaseDate=1676419200\" alt=\"Download on the App Store\" width=\"200\" height=\"60\" /></a></div>\n</div>\n<div class=\"clearfix\"></div>\n<hr />\n<div style=\"background: #e8eaf6; padding: 10px;\">\n<p><b><span style=\"color: #ff0000; margin-bottom: 10px;\">Important: </span></b>This mobile app is currently available for site administrators to manage the backend of their job postings and is only compatible with standard add-ons available on <a href=\"https://market.presstigers.com/\">market.presstigers.com</a></p>\n<p>If you have ideas that can help us to improve the mobile app and its user experience then please contact us at <a href=\"mailto:support@presstigers.com\">support@presstigers.com</a> or submit your query <a href=\"https://market.presstigers.com/contact-us/\">here</a>.</p>\n</div>\n<hr />\n<p><strong>Compatible Add-ons</strong></p>\n<div class=\"col-md-6\">\n<ul class=\"d-ul list2\">\n<li><a href=\"https://market.presstigers.com/product/email-application-add-on/\">Email Attachment Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/email-notification-templates-add-on/\">Email Notification Templates Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/individual-job-email-notifications-add-on/\">Individual Job Email Notifications Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/frontend-jobposting-add-on/\">Frontend Job Posting Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/job-board-captcha-add-on/\">Job Board CAPTCHA Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/job-search-box-add-on/\">Job Search Box Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/job-listings-import-export-add-on/\">Job Listings Import/Export Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/multiple-attachment-fields-add-on/\">Multiple Attachment Fields Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/extend-attachment-file-types-add-on/\">Extend Attachment File Types Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/job-application-deadline-add-on/\">Job Application Deadline Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/job-expirator-add-on/\">Job Expirator Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/salary-range-filter-add-on/\">Salary Range Filter Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/featured-job-listing-add-on/\">Featured Job Listing Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/google-job-search-and-indexing-api/\">Google Job Search and Indexing API</a></li>\n<li><a href=\"https://market.presstigers.com/product/geolocation-job-search-add-on/\">Geolocation Job Search Add-on</a></li>\n</ul>\n</div>\n<div class=\"col-md-6\">\n<ul class=\"d-ul list2\">\n<li><a href=\"https://market.presstigers.com/product/cloud-storage-connector-add-on/\">Cloud Storage Connector Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/refer-a-friend-add-on/\">Refer a Friend Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/how-to-apply-add-on/\">How to Apply Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/resume-preview-add-on/\">Resume Preview Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/custom-job-application-statuses-add-on/\">Custom Job Application Statuses Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/job-applications-csv-exporter/\">Job Applications CSV Exporter</a></li>\n<li><a href=\"https://market.presstigers.com/product/job-application-to-pdf-add-on/\">Job Application to PDF Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/job-applications-counter-add-on/\">Job Applications Counter Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/bulk-resume-download-add-on/\">Bulk Resume Download Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/category-base-hiring/\">Category Base Hiring</a></li>\n<li><a href=\"https://market.presstigers.com/product/location-base-hiring/\">Location Base Hiring</a></li>\n<li><a href=\"https://market.presstigers.com/product/job-level-filter-add-on/\">Job Level Filter Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/job-industry-filter-add-on/\">Job Industry Filter Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/company-filter-add-on/\">Company Details &amp; Filter Add-on</a></li>\n<li><a href=\"https://market.presstigers.com/product/remove-job-posted-date-add-on/\">Remove Job Posted Date Add-on</a></li>\n</ul>\n</div>\n\";s:17:\"short_description\";s:141:\"<p>The connector allows the site administrator to browse data stored in the Simple Job Board plugin directly from their mobile devices.</p>\n\";s:15:\"reviews_allowed\";b:1;s:14:\"average_rating\";s:4:\"0.00\";s:12:\"rating_count\";i:0;s:11:\"related_ids\";a:5:{i:0;i:160;i:1;i:446;i:2;i:27404;i:3;i:249;i:4;i:8401;}s:10:\"upsell_ids\";a:0:{}s:14:\"cross_sell_ids\";a:0:{}s:9:\"parent_id\";i:0;s:10:\"categories\";a:1:{i:0;s:16:\"Simple Job Board\";}s:4:\"tags\";a:0:{}s:6:\"images\";a:1:{i:0;a:7:{s:2:\"id\";i:60914;s:10:\"created_at\";s:20:\"2023-06-12T09:47:31Z\";s:10:\"updated_at\";s:20:\"2023-06-12T09:47:36Z\";s:3:\"src\";s:86:\"https://market.presstigers.com/wp-content/uploads/2023/02/MobileAppConnectorAdd-on.jpg\";s:5:\"title\";s:24:\"MobileAppConnectorAdd-on\";s:3:\"alt\";s:27:\"Mobile App Connector Add-on\";s:8:\"position\";i:0;}}s:12:\"featured_src\";s:86:\"https://market.presstigers.com/wp-content/uploads/2023/02/MobileAppConnectorAdd-on.jpg\";s:10:\"attributes\";a:1:{i:0;a:6:{s:4:\"name\";s:7:\"License\";s: