bile-app-connector.php\";}i:4;a:62:{s:5:\"title\";s:27:\"Job Seeker Dashboard Add-on\";s:2:\"id\";i:58559;s:10:\"created_at\";s:20:\"2023-04-13T07:27:58Z\";s:10:\"updated_at\";s:20:\"2025-11-11T17:48:14Z\";s:4:\"type\";s:8:\"variable\";s:6:\"status\";s:7:\"publish\";s:12:\"downloadable\";b:0;s:7:\"virtual\";b:0;s:9:\"permalink\";s:67:\"https://market.presstigers.com/product/job-seeker-dashboard-add-on/\";s:3:\"sku\";s:0:\"\";s:5:\"price\";s:2:\"35\";s:13:\"regular_price\";s:0:\"\";s:10:\"sale_price\";N;s:10:\"price_html\";s:417:\"<span class=\"woocommerce-Price-amount amount\" aria-hidden=\"true\"><bdi><span class=\"woocommerce-Price-currencySymbol\">&#36;</span>35.00</bdi></span> <span aria-hidden=\"true\">&ndash;</span> <span class=\"woocommerce-Price-amount amount\" aria-hidden=\"true\"><bdi><span class=\"woocommerce-Price-currencySymbol\">&#36;</span>99.00</bdi></span><span class=\"screen-reader-text\">Price range: &#36;35.00 through &#36;99.00</span>\";s:7:\"taxable\";b:0;s:10:\"tax_status\";s:7:\"taxable\";s:9:\"tax_class\";s:0:\"\";s:14:\"managing_stock\";b:0;s:14:\"stock_quantity\";N;s:8:\"in_stock\";b:1;s:18:\"backorders_allowed\";b:0;s:11:\"backordered\";b:0;s:17:\"sold_individually\";b:1;s:12:\"purchaseable\";b:1;s:8:\"featured\";b:0;s:7:\"visible\";b:1;s:18:\"catalog_visibility\";s:7:\"visible\";s:7:\"on_sale\";b:0;s:11:\"product_url\";s:0:\"\";s:11:\"button_text\";s:0:\"\";s:6:\"weight\";N;s:10:\"dimensions\";a:4:{s:6:\"length\";s:0:\"\";s:5:\"width\";s:0:\"\";s:6:\"height\";s:0:\"\";s:4:\"unit\";s:2:\"in\";}s:17:\"shipping_required\";b:1;s:16:\"shipping_taxable\";b:1;s:14:\"shipping_class\";s:0:\"\";s:17:\"shipping_class_id\";N;s:11:\"description\";s:2121:\"<p>Job Seeker Dashboard by <a href=\"https://presstigers.com\">PressTigers</a> is an add-on for the <a href=\"https://wordpress.org/plugins/simple-job-board/\">Simple Job Board</a> plugin, which allows job seekers to stay organized and on top of their job search. With this add-on, the job seeker can create their own profiles, save their resumes and set job preferences to apply for jobs that match their qualifications and interests.</p>\n<p>The dashboard also includes features to view listings of saved jobs, applied jobs, settings for job alerts and save job searches and create alerts that send new jobs via email weekly, or fortnightly.</p>\n<p>Following is the list of shortcodes for the configuration of the Job Seeker add-on:</p>\n<p><strong>Shortcodes List</strong></p>\n<ul class=\"d-ul list2\">\n<li>[jobseeker_signup] will show a form for the Job Seeker registration page.</li>\n<li>[jobseeker_dashboard] will show the Job Seeker dashboard.</li>\n<li>[jobseeker_login]  will show the Job Seeker login page.</li>\n</ul>\n<p><strong>User Authentication</strong></p>\n<ul class=\"d-ul list2\">\n<li>New User Registration/Login Page</li>\n<li>Admin set preference from Job Board &gt; Settings in order to approve new applicants via an activation link or approve from the dashboard.</li>\n</ul>\n<p><strong>Job Seeker Dashboard</strong><br />\nLogged in Job Seeker can manage:</p>\n<ul class=\"d-ul list2\">\n<li>Profile</li>\n<li>View the listing of saved jobs.</li>\n<li>View the listing of applied jobs.</li>\n<li>Set default resume and job preferences for alerts.</li>\n<li>Set the frequency of job alerts.</li>\n<li>Build a resume with the resume builder tool.</li>\n</ul>\n<p><strong>Apply for a Job</strong></p>\n<ul>\n<li>Auto-populate: When a job seeker is logged in, basic details like name and email will automatically appear in the job application.</li>\n<li>Resume: Job seekers should generate a PDF using the Resume Builder and upload it as the Default Resume. That resume will then automatically be included in the job application.</li>\n<li>Admins can enable a setting that allows only logged-in users to apply for a job.</li>\n</ul>\n\";s:17:\"short_description\";s:117:\"<p>Allow job seekers to create their own profiles, save their resumes and set job preferences to apply for jobs.</p>\n\";s:15:\"reviews_allowed\";b:1;s:14:\"average_rating\";s:4:\"0.00\";s:12:\"rating_count\";i:0;s:11:\"related_ids\";a:5:{i:0;i:27331;i:1;i:28087;i:2;i:27404;i:3;i:133;i:4;i:8401;}s:10:\"upsell_ids\";a:0:{}s:14:\"cross_sell_ids\";a:0:{}s:9:\"parent_id\";i:0;s:10:\"categories\";a:1:{i:0;s:16:\"Simple Job Board\";}s:4:\"tags\";a:0:{}s:6:\"images\";a:1:{i:0;a:7:{s:2:\"id\";i:59161;s:10:\"created_at\";s:20:\"2023-04-12T13:20:07Z\";s:10:\"updated_at\";s:20:\"2023-04-12T13:20:13Z\";s:3:\"src\";s:91:\"https://market.presstigers.com/wp-content/uploads/2023/04/JobSeekerDashboardBannerImage.jpg\";s:5:\"title\";s:29:\"JobSeekerDashboardBannerImage\";s:3:\"alt\";s:30:\"Job Seeker Add-on Banner Image\";s:8:\"position\";i:0;}}s:12:\"featured_src\";s:91:\"https://market.presstigers.com/wp-content/uploads/2023/04/JobSeekerDashboardBannerImage.jpg\";s:10:\"attributes\";a:1:{i:0;a:6:{s:4:\"name\";s:7:\"License\";s:4:\"slug\";s:7:\"license\";s:8:\"position\";i:0;s:7:\"visible\";b:1;s:9:\"variation\";b:1;s:7:\"options\";a:2:{i:0;s:7:\"Regular\";i:1;s:8:\"Extended\";}}}s:9:\"downloads\";a:0:{}s:14:\"download_limit\";i:-1;s:15:\"download_expiry\";i:365;s:13:\"download_type\";s:8:\"standard\";s:13:\"purchase_note\";s:0:\"\";s:11:\"total_sales\";i:37;s:10:\"variations\";a:2:{i:0;a:30:{s:2:\"id\";i:61456;s:10:\"created_at\";s:20:\"2023-09-05T09:10:38Z\";s:10:\"updated_at\";s:20:\"2024-12-03T17:54:59Z\";s:12:\"downloadable\";b:1;s:7:\"virtual\";b:1;s:9:\"permalink\";s:93:\"https://market.presstigers.com/product/job-seeker-dashboard-add-on/?attribute_license=Regular\";s:3:\"sku\";s:0:\"\";s:5:\"price\";s:2:\"35\";s:13:\"regular_price\";s:2:\"35\";s:10:\"sale_price\";N;s:7:\"taxable\";b:0;s:10:\"tax_status\";s:7:\"taxable\";s:9:\"tax_class\";s:0:\"\";s:14:\"managing_stock\";b:0;s:14:\"stock_quantity\";N;s:8:\"in_stock\";b:1;s:18:\"backorders_allowed\";b:0;s:11:\"backordered\";b:0;s:12:\"purchaseable\";b:1;s:7:\"visible\";b:1;s:7:\"on_sale\";b:0;s:6:\"weight\";N;s:10:\"dimensions