href=\"https://market.presstigers.com/wp-content/uploads/2025/09/SJB-add-on-for-Divi-Version-2-Documentation.pdf\">document</a> for guidance, and have Simple Job Board version 2.13.8 or later.</p>\n<p>Note: If you have updated the add-on to version 2.0 or higher, you will need to reconfigure the SJB Details module through the Theme Builder in the Divi menu as per the documentation given above.</p>\n<hr />\n<p><em><strong>If you have ideas that can help us improve our add-on and user experience, please contact us at support@presstigers.com or submit your query <a href=\"https://market.presstigers.com/contact-us/\">here</a>.</strong></em></p>\n\";s:17:\"short_description\";s:92:\"<p>Simple Job Board add-on to manage jobs listing and single job page via Divi modules.</p>\n\";s:15:\"reviews_allowed\";b:1;s:14:\"average_rating\";s:4:\"0.00\";s:12:\"rating_count\";i:0;s:11:\"related_ids\";a:5:{i:0;i:4296;i:1;i:27489;i:2;i:27404;i:3;i:28087;i:4;i:446;}s:10:\"upsell_ids\";a:0:{}s:14:\"cross_sell_ids\";a:0:{}s:9:\"parent_id\";i:0;s:10:\"categories\";a:1:{i:0;s:16:\"Simple Job Board\";}s:4:\"tags\";a:0:{}s:6:\"images\";a:1:{i:0;a:7:{s:2:\"id\";i:46004;s:10:\"created_at\";s:20:\"2022-04-25T15:49:15Z\";s:10:\"updated_at\";s:20:\"2022-04-25T15:49:36Z\";s:3:\"src\";s:95:\"https://market.presstigers.com/wp-content/uploads/2022/04/Job-Board-add-on-for-Divi-Builder.jpg\";s:5:\"title\";s:33:\"Job Board add-on for Divi Builder\";s:3:\"alt\";s:46:\"Job Board add-on for Divi Builder Banner Image\";s:8:\"position\";i:0;}}s:12:\"featured_src\";s:95:\"https://market.presstigers.com/wp-content/uploads/2022/04/Job-Board-add-on-for-Divi-Builder.jpg\";s:10:\"attributes\";a:1:{i:0;a:6:{s:4:\"name\";s:7:\"License\";s:4:\"slug\";s:7:\"license\";s:8:\"position\";i:0;s:7:\"visible\";b:1;s:9:\"variation\";b:1;s:7:\"options\";a:2:{i:0;s:7:\"Regular\";i:1;s:8:\"Extended\";}}}s:9:\"downloads\";a:0:{}s:14:\"download_limit\";i:-1;s:15:\"download_expiry\";i:365;s:13:\"download_type\";s:8:\"standard\";s:13