iable\";s:6:\"status\";s:7:\"publish\";s:12:\"downloadable\";b:0;s:7:\"virtual\";b:0;s:9:\"permalink\";s:73:\"https://market.presstigers.com/product/job-listings-import-export-add-on/\";s:3:\"sku\";s:0:\"\";s:5:\"price\";s:2:\"20\";s:13:\"regular_price\";s:0:\"\";s:10:\"sale_price\";N;s:10:\"price_html\";s:417:\"<span class=\"woocommerce-Price-amount amount\" aria-hidden=\"true\"><bdi><span class=\"woocommerce-Price-currencySymbol\">&#36;</span>20.00</bdi></span> <span aria-hidden=\"true\">&ndash;</span> <span class=\"woocommerce-Price-amount amount\" aria-hidden=\"true\"><bdi><span class=\"woocommerce-Price-currencySymbol\">&#36;</span>59.00</bdi></span><span class=\"screen-reader-text\">Price range: &#36;20.00 through &#36;59.00</span>\";s:7:\"taxable\";b:0;s:10:\"tax_status\";s:7:\"taxable\";s:9:\"tax_class\";s:0:\"\";s:14:\"managing_stock\";b:0;s:14:\"stock_quantity\";N;s:8:\"in_stock\";b:1;s:18:\"backorders_allowed\";b:0;s:11:\"backordered\";b:0;s:17:\"sold_individually\";b:1;s:12:\"purchaseable\";b:1;s:8:\"featured\";b:0;s:7:\"visible\";b:1;s:18:\"catalog_visibility\";s:7:\"visible\";s:7:\"on_sale\";b:0;s:11:\"product_url\";s:0:\"\";s:11:\"button_text\";s:0:\"\";s:6:\"weight\";N;s:10:\"dimensions\";a:4:{s:6:\"length\";s:0:\"\";s:5:\"width\";s:0:\"\";s:6:\"height\";s:0:\"\";s:4:\"unit\";s:2:\"in\";}s:17:\"shipping_required\";b:1;s:16:\"shipping_taxable\";b:1;s:14:\"shipping_class\";s:0:\"\";s:17:\"shipping_class_id\";N;s:11:\"description\";s:1004:\"<p>If you\'re looking to add such functionality that\'ll help you import and export jobs from the SJB, then this is the right add-on for you. Job Listings Import/Export Add-on is easy to install and lightweight add-on that not only imports the jobs but also exports them into a CSV and an XML. You can also export jobs between two dates i.e Start date and End date, Job Categories, Job Locations, and Status.</p>\n<p><strong>Note: </strong><strong>CSV File Must Be UTF-8 or UTF-8 Compatible</strong></p>\n<p>As there is no other way to specify the character encoding for a CSV file, we will consider all uploaded CSV files are UFT-8 as a standard encoding for the web.</p>\n<p>This should work most of the time, however, if you\'re importing a CSV file with some special characters such as umlauts, non-Latin characters, etc and those characters are not appearing correctly in the job, we would recommend you try opening your CSV file in a text editor using the correct encoding and then save it by UFT-8.</p>\n\";s:17:\"short_description\";s:61:\"<p>Import/Export job listings from/to CSV and XML files.</p>\n\";s:15:\"reviews_allowed\";b:1;s:14:\"average_rating\";s:4:\"0.00\";s:12:\"rating_count\";i:0;s:11:\"related_ids\";a:5:{i:0;i:774;i:1;i:114;i:2;i:27073;i:3;i:27489;i:4;i:27407;}s:10:\"upsell_ids\";a:0:{}s:14:\"cross_sell_ids\";a:0:{}s:9:\"parent_id\";i:0;s:10:\"categories\";a:1:{i:0;s:16:\"Simple Job Board\";}s:4:\"tags\";a:0:{}s:6:\"images\";a:1:{i:0;a:7:{s:2:\"id\";i:36508;s:10:\"created_at\";s:20:\"2021-07-20T18:47:33Z\";s:10:\"updated_at\";s:20:\"2021-07-20T18:48:03Z\";s:3:\"src\";s:103:\"https://market.presstigers.com/wp-content/uploads/2021/07/JobListingsImportExportAdd-on-BannerImage.jpg\";s:5:\"title\";s:41:\"JobListingsImportExportAdd-on-BannerImage\";s:3:\"alt\";s:39:\"Job Listings Import Export Banner Image\";s:8:\"position\";i:0;}}s:12:\"featured_src\";s:103:\"https://market.presstigers.com/wp-content/uploads/2021/07/JobListingsImportExportAdd-on-BannerImage.jpg\";s:10:\"attributes\";a:1:{i:0;a:6:{s:4:\"name\";s:7:\"License\";s:4:\"slug\";s:7:\"license\";s:8:\"position\";i:0;s:7:\"visible\";b:1;s:9:\"variation\";b:1;s:7:\"options\";a:2:{i:0;s:7:\"Regular\";i:1;s:8:\"Extended\";}}}s:9:\"downloads\";a:0:{}s:14:\"download_limit\";i:-1;s:15:\"download_expiry\";i:365;s:13:\"download_type\";s:8:\"standard\";s:13:\"purchase_note\";s:0:\"\";s:11:\"total_sales\";i:91;s:10:\"variations\";a:2:{i:0;a:30:{s:2:\"id\";i:61479;s:10:\"created_at\";s:20:\"2023-09-05T09:10:42Z\";s:10:\"updated_a