wnload_expiry\";i:365;}}s:6:\"parent\";a:0:{}s:16:\"grouped_products\";a:0:{}s:10:\"menu_order\";i:20;s:14:\"add_on_version\";s:5:\"1.2.0\";s:16:\"plugin_main_slug\";s:0:\"\";s:16:\"_linked_products\";a:3:{i:0;s:23:\"Email Attachment Add-on\";i:1;s:33:\"Multiple Attachment Fields Add-on\";i:2;s:20:\"Job Expirator Add-on\";}}i:18;a:63:{s:5:\"title\";s:25:\"Job Board - 4 in 1 Bundle\";s:2:\"id\";i:41587;s:10:\"created_at\";s:20:\"2021-11-25T13:30:21Z\";s:10:\"updated_at\";s:20:\"2025-04-21T11:36:24Z\";s:4:\"type\";s:8:\"variable\";s:6:\"status\";s:7:\"publish\";s:12:\"downloadable\";b:0;s:7:\"virtual\";b:0;s:9:\"permalink\";s:63:\"https://market.presstigers.com/product/job-board-4-in-1-bundle/\";s:3:\"sku\";s:0:\"\";s:5:\"price\";s:2:\"55\";s:13:\"regular_price\";s:0:\"\";s:10:\"sale_price\";N;s:10:\"price_html\";s:419:\"<span class=\"woocommerce-Price-amount amount\" aria-hidden=\"true\"><bdi><span class=\"woocommerce-Price-currencySymbol\">&#36;</span>55.00</bdi></span> <span aria-hidden=\"true\">&ndash;</span> <span class=\"woocommerce-Price-amount amount\" aria-hidden=\"true\"><bdi><span class=\"woocommerce-Price-currencySymbol\">&#36;</span>169.00</bdi></span><span class=\"screen-reader-text\">Price range: &#36;55.00 through &#36;169.00</span>\";s:7:\"taxable\";b:0;s:10:\"tax_status\";s:7:\"taxable\";s:9:\"tax_class\";s:0:\"\";s:14:\"managing_stock\";b:0;s:14:\"stock_quantity\";N;s:8:\"in_stock\";b:1;s:18:\"backorders_allowed\";b:0;s:11:\"backordered\";b:0;s:17:\"sold_individually\";b:1;s:12:\"purchaseable\";b:1;s:8:\"featured\";b:0;s:7:\"visible\";b:1;s:18:\"catalog_visibility\";s:7:\"visible\";s:7:\"on_sale\";b:1;s:11:\"product_url\";s:0:\"\";s:11:\"button_text\";s:0:\"\";s:6:\"weight\";N;s:10:\"dimensions\";a:4:{s:6:\"length\";s:0:\"\";s:5:\"width\";s:0:\"\";s:6:\"height\";s:0:\"\";s:4:\"unit\";s:2:\"in\";}s:17:\"shipping_required\";b:1;s:16:\"shipping_taxable\";b:1;s:14:\"shipping_class\";s:0:\"\";s:17:\"shipping_class_id\";N;s:11:\"description\";s:2350:\"<p>PressTigers now brings you the 4 in 1 bundle add-ons for its users!</p>\n<p>The 4 in 1 bundle contains 4 Add-ons i.e Email Attachment, Multiple Attachment Fields, Extend Attachment File Types, and Email Notification Templates add-ons.</p>\n<p>The best thing is, you can get all of them in a single purchase and at a discounted price.</p>\n<p>Following are details of the bundle add-ons:</p>\n<p>The <a href=\"https://market.presstigers.com/product/email-application-add-on/\">Email Attachment</a> add-on sends the uploaded resume of an applicant to Admin, HR &amp; Job Author via email. By using this add-on, you can get rid of the website login to receive the applicant’s request. You can also enable/disable receiving the applicant’s resume attachment through email using the global settings.</p>\n<p><strong>Note:</strong> <em><strong>If you are not getting emails then please install any SMTP plugin and configure it with your email account.</strong></em></p>\n<p>The <a href=\"https://market.presstigers.com/product/multiple-attachment-fields-add-on/\">Multiple Attachment Fields</a> add-on adds a “file” field type in the job application form builder. You can add multiple file upload fields on the job application form via the dashboard. You can also set fields as optional or mandatory.</p>\n<p><em><strong>Note: It only supports the extensions (.pdf, .doc, .docx, .odt, .txt, .rtf) as per one Uploaded File settings.</strong></em></p>\n<p>The<a href=\"https://market.presstigers.com/product/extend-attachment-file-types-add-on/\"> Extend Attachment File Types</a> add-on extends the portfolio of Simple Job Board to accept more files with different extensions by allowing you to add custom file types instead of only using predefined ones.</p>\n<p>Once you’ve uploaded the add-on, you’ll be able to add new extensions, update added extensions as well as delete extensions through the settings of the Simple Job Board.</p>\n<p>The <a href=\"https://market.presstigers.com/product/email-notification-templates-add-on/\">Email Notification Templates</a> add-on makes the email notifications more personalized by allowing you to write custom email templates instead of the predefined ones. Once you’ve uploaded the add-on, you’ll be able to change email templates for Applicant, HR, and Admin through the settings of the Simple Job Board.</p>\n\";s:17:\"short_description\";s:166:\"<p>Job Board &#8211; 4 in 1 solution has the Email Attachment, Multiple Attachment Fields, Extend Attachment File Types and Email Notification Templates add-ons.</p>\n\";s:15:\"reviews_allowed\";b:1;s:14:\"average_rating\";s:4:\"0.00\";s:12:\"rating_count\";i:0;s:11:\"related_ids\";a:5:{i:0;i:106;i:1;i:104;i:2;i:691;i:3;i:133;i:4;i:157;}s:10:\"upsell_ids\";a:0:{}s:14:\"cross_sell_ids\";a:0:{}s:9:\"parent_id\";i:0;s:10:\"categories\";a:1:{i:0;s:16:\"Simple Job Board\";}s:4:\"tags\";a:0:{}s:6:\"images\";a:1:{i:0;a:7:{s:2:\"id\";i:41589;s:10:\"created_at\";s:20:\"2021-11-25T13:08:27Z\";s:10:\"updated_at\";s:20:\"2021-11-25T13:09:13Z\";s:3:\"src\";s:81:\"https://market.presstigers.com/wp-content/uploads/2021/11/JobBoard-4in1Bundle.jpg\";s:5:\"title\";s:19:\"JobBoard-4in1Bundle\";s:3:\"alt\";s:36:\"Job Board - 4 in1Bundle Banner Image\";s:8:\"position\";i:0;}}s:12:\"featured_src\";s:81:\"https://market.presstigers.com/wp-content/uploads/2021/11/JobBoard-4in1Bundle.jpg\";s:10:\"attributes\";a:1:{i:0;a:6:{s:4:\"name\";s:7:\"License\";s:4:\"slug\";s:7:\"license\";s:8:\"position\";i:0;s:7:\"visible\";b:1;s:9:\"variation\";b:1;s:7:\"options\";a:2:{i:0;s:7:\"Regular\";i:1;s:8:\"Extended\";}}}s:9:\"downloads\";a:0:{}s:14:\"download_limit\";i:-1;s:15:\"download_expiry\";i:365;s:13:\"download_type\";s:8:\"standard\";s:13:\"purchase_note\";s:0:\"\";s:11:\"total_sales\";i:0;s:10:\"variations\";a:2:{i:0;a:30:{s:2:\"id\";i:61482;s:10:\"created_at\";s:20:\"2023-09-05T09:10:42Z\";s:10:\"updated_at\";s:20:\"2023-09-11T13:07:56Z\";s:12:\"downloadable\";b:1;s:7:\"virtual\";b:1;s:9:\"permalink\";s:89:\"https:/