(1216, 140, '_form', '<div class=\"fnote\">Fields marked <span class=\"req\">*</span> are required.</div>\n\n<div class=\"frow\">\n  <div class=\"field\">\n    <label>FULL NAME <span class=\"req\">*</span></label>\n    [text* name placeholder \"Your name\"]\n  </div>\n  <div class=\"field\">\n    <label>WORK EMAIL <span class=\"req\">*</span></label>\n    [email* email placeholder \"you@organization.gov.sa\"]\n  </div>\n</div>\n\n<div class=\"frow\">\n  <div class=\"field\">\n    <label>ORGANIZATION <span class=\"req\">*</span></label>\n    [text* org placeholder \"Entity / company\"]\n  </div>\n  <div class=\"field\">\n    <label>JOB TITLE <span class=\"req\">*</span></label>\n    [text* title placeholder \"Your role\"]\n  </div>\n</div>\n\n<div class=\"frow\">\n  <div class=\"field\">\n    <label>AREA OF INTEREST <span class=\"req\">*</span></label>\n    [select* area include_blank \"Enterprise Modernization\" \"Smart City Operations\" \"AI & Automation\" \"Cybersecurity\" \"Managed Services\"]\n  </div>\n  <div class=\"field\">\n    <label>PHONE NUMBER <span class=\"req\">*</span></label>\n    [tel* phone placeholder \"+966 …\"]\n  </div>\n</div>\n\n<div class=\"frow\">\n  <div class=\"field ffull\">\n    <label>BUSINESS CHALLENGE (OPTIONAL)</label>\n    [textarea message placeholder \"What outcome are you driving toward?\"]\n  </div>\n</div>\n\n[submit class:fsubmit \"Talk to an expert →\"]\n\n<div class=\"fbot\">You\'ll be assigned a solution owner who reaches out within one business day.</div>'),
(1217, 140, '_mail', 'a:9:{s:6:\"active\";b:1;s:7:\"subject\";s:30:\"[_site_title] \"[your-subject]\"\";s:6:\"sender\";s:39:\"[_site_title] <r.amira@leadergroup.com>\";s:9:\"recipient\";s:19:\"[_site_admin_email]\";s:4:\"body\";s:191:\"From: [your-name] [your-email]\nSubject: [your-subject]\n\nMessage Body:\n[your-message]\n\n-- \nThis is a notification that a contact form was submitted on your website ([_site_title] [_site_url]).\";s:18:\"additional_headers\";s:22:\"Reply-To: [your-email]\";s:11:\"attachments\";s:0:\"\";s:8:\"use_html\";b:1;s:13:\"exclude_blank\";b:1;}'),
(1218, 140, '_mail_2', 'a:9:{s:6:\"active\";b:0;s:7:\"subject\";s:30:\"[_site_title] \"[your-subject]\"\";s:6:\"sender\";s:39:\"[_site_title] <r.amira@leadergroup.com>\";s:9:\"recipient\";s:12:\"[your-email]\";s:4:\"body\";s:220:\"Message Body:\n[your-message]\n\n-- \nThis email is a receipt for your contact form submission on our website ([_site_title] [_site_url]) in which your email address was used. If that was not you, please ignore this message.\";s:18:\"additional_headers\";s:29:\"Reply-To: [_site_admin_email]\";s:11:\"attachments\";s:0:\"\";s:8:\"use_html\";b:1;s:13:\"exclude_blank\";b:1;}'),
(1219, 140, '_messages', 'a:22:{s:12:\"mail_sent_ok\";s:67:\"Thank you. A solution owner will reach out within one business day.\";s:12:\"mail_sent_ng\";s:71:\"There was an error trying to send your message. Please try again later.\";s:16:\"validation_error\";s:61:\"One or more fields have an error. Please check and try again.\";s:4:\"spam\";s:71:\"There was an error trying to send your message. Please try again later.\";s:12:\"accept_terms\";s:69:\"You must accept the terms and conditions before sending your message.\";s:16:\"invalid_required\";s:27:\"Please fill out this field.\";s:16:\"invalid_too_long\";s:32:\"This field has a too long input.\";s:17:\"invalid_too_short\";s:33:\"This field has a too short input.\";s:13:\"upload_failed\";s:46:\"There was an unknown error uploading the file.\";s:24:\"upload_file_type_invalid\";s:49:\"You are not allowed to upload files of this type.\";s:21:\"upload_file_too_large\";s:31:\"The uploaded file is too large.\";s:23:\"upload_failed_php_error\";s:38:\"There was an error uploading the file.\";s:12:\"invalid_date\";s:41:\"Please enter a date in YYYY-MM-DD format.\";s:14:\"date_too_early\";s:32:\"This field has a too early date.\";s:13:\"date_too_late\";s:31:\"This field has a too late date.\";s:14:\"invalid_number\";s:22:\"Please enter a number.\";s:16:\"number_too_small\";s:34:\"This field has a too small number.\";s:16:\"number_too_large\";s:34:\"This field has a too large number.\";s:23:\"quiz_answer_not_correct\";s:36:\"The answer to the quiz is incorrect.\";s:13:\"invalid_email\";s:30:\"Please enter an email address.\";s:11:\"invalid_url\";s:19:\"Please enter a URL.\";s:11:\"invalid_tel\";s:32:\"Please enter a telephone number.\";}'),
