(10695, 673, '_hero_section', 'field_hero_section'),
(10696, 673, 'overview', 'Defense and security organizations operate in highly demanding environments where resilience, situational awareness, cybersecurity, and operational readiness are mission critical. LESYS delivers secure, integrated, and intelligence-driven solutions that support operational effectiveness and national security objectives.'),
(10697, 673, '_overview', 'field_overview'),
(10698, 673, 'how_we_help', '•	Command and control solutions \r\n•	Situational awareness platforms \r\n•	Cybersecurity operations centers \r\n•	Secure communications infrastructure \r\n•	Operational intelligence systems \r\n•	Critical infrastructure protection \r\n•	Data integration and analytics \r\n•	Mission support technologies '),
(10699, 673, '_how_we_help', 'field_how_we_help'),
(10700, 673, 'key_outcomes', '•	Enhanced operational readiness \r\n•	Improved situational awareness \r\n•	Faster response and coordination \r\n•	Increased cybersecurity resilience \r\n•	Better information sharing \r\n•	Greater operational effectiveness \r\n•	Improve public safety and internal security\r\n•	Deliver faster, digital citizen services\r\n•	Strengthening law enforcement capabilities\r\n•	Enable real-time data sharing across agencies\r\n•	Reduce fraud in identity and civil services\r\n•	Enhance border control and immigration management'),
(10701, 673, '_key_outcomes', 'field_key_outcomes'),
(10702, 673, 'operational_impact', 'Organizations gain unified visibility across operations, assets, personnel, and security environments, enabling informed decisions and coordinated responses to evolve situations.'),
(10703, 673, '_operational_impact', 'field_operational_impact'),
(10704, 673, 'why_lesys', 'We combine advanced technologies, secure architectures, and operational expertise to support mission-critical defense and security operations.'),
