(11447, 708, 'how_we_help', '•	Health information systems\r\n•	Electronic medical records (EMR)\r\n•	PACS system\r\n•	Joint Commission International (JCI)\r\n•	Healthcare digital transformation \r\n•	Smart hospital operations \r\n•	Infrastructure and cloud modernization \r\n•	Healthcare cybersecurity programs \r\n•	Operational command centers \r\n•	Contact center and patient engagement solutions \r\n•	Data analytics and reporting platforms \r\n•	Facility and asset management systems \r\n'),
(11448, 708, '_how_we_help', 'field_how_we_help'),
(11449, 708, 'key_outcomes', '•	Improved patient experiences \r\n•	Enhanced operational efficiency \r\n•	Better clinical and administrative coordination \r\n•	Increased infrastructure reliability \r\n•	Stronger cybersecurity and compliance \r\n•	Optimized resource utilization \r\n'),
(11450, 708, '_key_outcomes', 'field_key_outcomes'),
(11451, 708, 'operational_impact', 'Healthcare organizations achieve greater visibility into operations, assets, facilities, and patient service workflows. Decision-makers gain access to actionable insights that improve care delivery and operational performance.'),
(11452, 708, '_operational_impact', 'field_operational_impact'),
(11453, 708, 'why_lesys', 'We understand the unique challenges of healthcare environments and provide secure, scalable, and operationally focused solutions that support patient care and organizational excellence.'),
(11454, 708, '_why_lesys', 'field_why_lesys'),
