(11575, 670, 'overview', 'Utility providers must balance operational reliability, infrastructure performance, sustainability goals, and increasing service demands. LESYS helps utility organizations modernize operations through intelligent monitoring, automation, predictive maintenance, and integrated operational control.'),
(11576, 670, '_overview', 'field_overview'),
(11577, 670, 'how_we_help', '•	Utility operations centers \r\n•	Asset monitoring and management \r\n•	Predictive maintenance solutions \r\n•	IoT-enabled infrastructure monitoring \r\n•	Workforce and field operations management \r\n•	Data analytics and operational intelligence \r\n•	Infrastructure modernization programs \r\n•	Cybersecurity for critical infrastructure \r\n'),
(11578, 670, '_how_we_help', 'field_how_we_help'),
(11579, 670, 'key_outcomes', '•	Increased service reliability and uptime \r\n•	Improved asset performance and lifespan \r\n•	Reduced operational costs \r\n•	Faster fault detection and resolution \r\n•	Enhanced workforce productivity \r\n•	Greater operational resilience \r\n'),
(11580, 670, '_key_outcomes', 'field_key_outcomes'),
(11581, 670, 'operational_impact', 'Utilities gain greater visibility into network performance, infrastructure health, and operational risks. Teams can proactively manage assets, reduce outages, optimize maintenance activities, and improve service continuity.'),
(11582, 670, '_operational_impact', 'field_operational_impact'),
(11583, 670, 'why_lesys', 'We help utility providers transform critical infrastructure operations into intelligent, resilient, and highly efficient service environments.'),
