(11693, 711, 'hero_section', ''),
(11694, 711, '_hero_section', 'field_hero_section'),
(11695, 711, 'overview', 'Utility providers must balance operational reliability, infrastructure performance, sustainability goals, and increasing service demands. LESYS helps utility organizations modernize operations through intelligent monitoring, automation, predictive maintenance, and integrated operational control.'),
(11696, 711, '_overview', 'field_overview'),
(11697, 711, 'how_we_help', '•	Utility operations centers \r\n•	Asset monitoring and management \r\n•	Predictive maintenance solutions \r\n•	IoT-enabled infrastructure monitoring \r\n•	Workforce and field operations management \r\n•	Data analytics and operational intelligence \r\n•	Infrastructure modernization programs \r\n•	Cybersecurity for critical infrastructure \r\n'),
(11698, 711, '_how_we_help', 'field_how_we_help'),
(11699, 711, 'key_outcomes', '•	Increased service reliability and uptime \r\n•	Improved asset performance and lifespan \r\n•	Reduced operational costs \r\n•	Faster fault detection and resolution \r\n•	Enhanced workforce productivity \r\n•	Greater operational resilience \r\n'),
(11700, 711, '_key_outcomes', 'field_key_outcomes');
