(11823, 246, 'hero_section', ''),
(11824, 246, '_hero_section', 'field_hero_section'),
(11825, 246, 'overview', 'Municipalities are responsible for managing diverse city services, infrastructure, assets, field operations, and citizen interactions. LESYS enables municipalities to transition from fragmented operations to integrated smart city ecosystems that improve service quality, sustainability, and urban resilience.'),
(11826, 246, '_overview', 'field_overview'),
(11827, 246, 'how_we_help', '•	Smart city strategy and implementation \r\n•	City Operations Centers (COP) \r\n•	Smart cleaning and waste management operations \r\n•	Smart inspection and compliance programs \r\n•	Intelligent field workforce management \r\n•	Urban IoT and sensor integration \r\n•	Citizen engagement platforms \r\n•	Municipal performance management systems \r\n'),
(11828, 246, '_how_we_help', 'field_how_we_help'),
(11829, 246, 'key_outcomes', '•	Improved city-wide operational visibility \r\n•	Faster incident detection and response \r\n•	Enhanced citizen satisfaction \r\n•	Increased operational efficiency \r\n•	Better management of municipal assets and resources \r\n•	More sustainable urban operations \r\n'),
(11830, 246, '_key_outcomes', 'field_key_outcomes'),
(11831, 246, 'operational_impact', 'Municipal leaders gain a real-time operational view of city services, enabling proactive management of infrastructure, public spaces, utilities, inspections, and field operations. Service delivery becomes measurable, accountable, and data-driven.'),
(11832, 246, '_operational_impact', 'field_operational_impact'),
(11833, 246, 'why_lesys', 'Our combination of smart city technologies, municipal operations expertise, and integrated platforms enables cities to operate more efficiently while delivering better experiences for residents and visitors.'),
(11834, 246, '_why_lesys', 'field_why_lesys'),
