(11946, 714, '_overview', 'field_overview'),
(11947, 714, 'how_we_help', '•	Smart city strategy and implementation \r\n•	City Operations Centers (COP) \r\n•	Smart cleaning and waste management operations \r\n•	Smart inspection and compliance programs \r\n•	Intelligent field workforce management \r\n•	Urban IoT and sensor integration \r\n•	Citizen engagement platforms \r\n•	Municipal performance management systems \r\n'),
(11948, 714, '_how_we_help', 'field_how_we_help'),
(11949, 714, 'key_outcomes', '•	Improved city-wide operational visibility \r\n•	Faster incident detection and response \r\n•	Enhanced citizen satisfaction \r\n•	Increased operational efficiency \r\n•	Better management of municipal assets and resources \r\n•	More sustainable urban operations \r\n'),
(11950, 714, '_key_outcomes', 'field_key_outcomes'),
(11951, 714, 'operational_impact', 'Municipal leaders gain a real-time operational view of city services, enabling proactive management of infrastructure, public spaces, utilities, inspections, and field operations. Service delivery becomes measurable, accountable, and data-driven.'),
