(12187, 716, 'hero_section_cta_button_1_url', 'https://beta.lesys.com/industry/municipalities-smart-cities/#contact'),
(12188, 716, '_hero_section_cta_button_1_url', 'field_6a3bb12dad45e'),
(12189, 716, 'hero_section_cta_button_2_url', 'https://beta.lesys.com/industries'),
(12190, 716, '_hero_section_cta_button_2_url', 'field_6a3bb208b2a2d'),
(12191, 716, 'hero_section', ''),
(12192, 716, '_hero_section', 'field_hero_section'),
(12193, 716, 'overview', 'Municipalities are responsible for managing diverse city services, infrastructure, assets, field operations, and citizen interactions. LESYS enables municipalities to transition from fragmented operations to integrated smart city ecosystems that improve service quality, sustainability, and urban resilience.'),
(12194, 716, '_overview', 'field_overview'),
(12195, 716, 'how_we_help', '•	Smart city strategy and implementation \r\n•	City Operations Centers (COP) \r\n•	Smart cleaning and waste management operations \r\n•	Smart inspection and compliance programs \r\n•	Intelligent field workforce management \r\n•	Urban IoT and sensor integration \r\n•	Citizen engagement platforms \r\n•	Municipal performance management systems \r\n'),
(12196, 716, '_how_we_help', 'field_how_we_help'),
(12197, 716, 'key_outcomes', '•	Improved city-wide operational visibility \r\n•	Faster incident detection and response \r\n•	Enhanced citizen satisfaction \r\n•	Increased operational efficiency \r\n•	Better management of municipal assets and resources \r\n•	More sustainable urban operations \r\n'),
(12198, 716, '_key_outcomes', 'field_key_outcomes'),
(12199, 716, 'operational_impact', 'Municipal leaders gain a real-time operational view of city services, enabling proactive management of infrastructure, public spaces, utilities, inspections, and field operations. Service delivery becomes measurable, accountable, and data-driven.'),
(12200, 716, '_operational_impact', 'field_operational_impact'),
(12201, 716, 'why_lesys', 'Our combination of smart city technologies, municipal operations expertise, and integrated platforms enables cities to operate more efficiently while delivering better experiences for residents and visitors.'),
(12202, 716, '_why_lesys', 'field_why_lesys'),
(12203, 716, 'sucess_heading', 'Customer Success Story'),
