(12310, 247, '_hero_section_subtitle', 'field_hero_subtitle'),
(12311, 247, 'hero_section_short_description', 'Government entities are under increasing pressure to deliver efficient, transparent, secure, and citizen-centric services while managing complex regulatory requirements and growing public expectations. '),
(12312, 247, '_hero_section_short_description', 'field_hero_short_desc'),
(12313, 247, 'hero_section_cta_button_1_text', 'Contact Us'),
(12314, 247, '_hero_section_cta_button_1_text', 'field_6a3bb103ad45d'),
(12315, 247, 'hero_section_cta_button_2_text', 'Explore Industries'),
(12316, 247, '_hero_section_cta_button_2_text', 'field_6a3bb17aad45f'),
(12317, 247, 'hero_section_cta_button_1_url', 'https://beta.lesys.com/industry/government-public-sector/#contact'),
(12318, 247, '_hero_section_cta_button_1_url', 'field_6a3bb12dad45e'),
(12319, 247, 'hero_section_cta_button_2_url', 'https://beta.lesys.com/industries'),
(12320, 247, '_hero_section_cta_button_2_url', 'field_6a3bb208b2a2d'),
(12321, 247, 'hero_section', ''),
(12322, 247, '_hero_section', 'field_hero_section'),
(12323, 247, 'overview', 'Government entities are under increasing pressure to deliver efficient, transparent, secure, and citizen-centric services while managing complex regulatory requirements and growing public expectations. LESYS helps government organizations modernize operations, accelerate digital transformation, improve service delivery, and enhance decision-making through integrated technology, operational excellence, and data-driven governance.'),
(12324, 247, '_overview', 'field_overview'),
(12325, 247, 'how_we_help', '•	Digital government transformation initiatives \r\n•	National and regional command center solutions \r\n•	Citizen service modernization \r\n•	Government cloud and infrastructure services \r\n•	Cybersecurity and digital resilience programs \r\n•	Data governance and analytics platforms \r\n•	Smart workforce and operational management \r\n•	Integrated digital service delivery platforms \r\n'),
(12326, 247, '_how_we_help', 'field_how_we_help'),
(12327, 247, 'key_outcomes', '•	Improved citizen experience and service accessibility \r\n•	Enhanced transparency and accountability \r\n•	Faster decision-making through real-time intelligence \r\n•	Increased operational efficiency across departments \r\n•	Stronger cybersecurity and compliance posture \r\n•	Better utilization of public resources \r\n'),
(12328, 247, '_key_outcomes', 'field_key_outcomes');
INSERT INTO `lesys_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES
(12329, 247, 'operational_impact', 'Government organizations gain a unified operational environment where services, data, processes, and stakeholders are connected. Decision-makers have access to real-time insights, operational visibility, and performance metrics that support more effective governance and policy execution.'),
(12330, 247, '_operational_impact', 'field_operational_impact'),
(12331, 247, 'why_lesys', 'We combine deep public-sector understanding with advanced technologies and operational expertise to help governments deliver measurable improvements in efficiency, service quality, and public trust.'),
(12332, 247, '_why_lesys', 'field_why_lesys'),
