(12430, 719, '_hero_section_subtitle', 'field_hero_subtitle'),
(12431, 719, 'hero_section_short_description', 'Government entities are under increasing pressure to deliver efficient, transparent, secure, and citizen-centric services while managing complex regulatory requirements and growing public expectations. '),
(12432, 719, '_hero_section_short_description', 'field_hero_short_desc'),
(12433, 719, 'hero_section_cta_button_1_text', 'Contact Us'),
(12434, 719, '_hero_section_cta_button_1_text', 'field_6a3bb103ad45d'),
(12435, 719, 'hero_section_cta_button_2_text', 'Explore Industries'),
(12436, 719, '_hero_section_cta_button_2_text', 'field_6a3bb17aad45f'),
(12437, 719, 'hero_section_cta_button_1_url', 'https://beta.lesys.com/industry/government-public-sector/#contact'),
(12438, 719, '_hero_section_cta_button_1_url', 'field_6a3bb12dad45e'),
(12439, 719, 'hero_section_cta_button_2_url', 'https://beta.lesys.com/industries'),
(12440, 719, '_hero_section_cta_button_2_url', 'field_6a3bb208b2a2d'),
(12441, 719, 'hero_section', ''),
(12442, 719, '_hero_section', 'field_hero_section'),
(12443, 719, 'overview', 'Government entities are under increasing pressure to deliver efficient, transparent, secure, and citizen-centric services while managing complex regulatory requirements and growing public expectations. LESYS helps government organizations modernize operations, accelerate digital transformation, improve service delivery, and enhance decision-making through integrated technology, operational excellence, and data-driven governance.'),
(12444, 719, '_overview', 'field_overview'),
(12445, 719, 'how_we_help', '•	Digital government transformation initiatives \r\n•	National and regional command center solutions \r\n•	Citizen service modernization \r\n•	Government cloud and infrastructure services \r\n•	Cybersecurity and digital resilience programs \r\n•	Data governance and analytics platforms \r\n•	Smart workforce and operational management \r\n•	Integrated digital service delivery platforms \r\n'),
(12446, 719, '_how_we_help', 'field_how_we_help'),
(12447, 719, 'key_outcomes', '•	Improved citizen experience and service accessibility \r\n•	Enhanced transparency and accountability \r\n•	Faster decision-making through real-time intelligence \r\n•	Increased operational efficiency across departments \r\n•	Stronger cybersecurity and compliance posture \r\n•	Better utilization of public resources \r\n'),
(12448, 719, '_key_outcomes', 'field_key_outcomes'),
(12449, 719, 'operational_impact', 'Government organizations gain a unified operational environment where services, data, processes, and stakeholders are connected. Decision-makers have access to real-time insights, operational visibility, and performance metrics that support more effective governance and policy execution.'),
(12450, 719, '_operational_impact', 'field_operational_impact'),
(12451, 719, 'why_lesys', 'We combine deep public-sector understanding with advanced technologies and operational expertise to help governments deliver measurable improvements in efficiency, service quality, and public trust.'),
(12452, 719, '_why_lesys', 'field_why_lesys'),
(12453, 719, 'sucess_heading', 'Customer Success Story'),
(12454, 719, '_sucess_heading', 'field_6a34092d6a214'),
(12455, 719, 'success_title1', 'Entire Cities, Operated From'),
(12456, 719, '_success_title1', 'field_6a3409786a215'),
(12457, 719, 'success_title2', 'a Single'),
(12458, 719, '_success_title2', 'field_6a34098e6a216'),
(12459, 719, 'success_title3', 'Command Center'),
(12460, 719, '_success_title3', 'field_6a3409a26a217'),
(12461, 719, 'story_columns_story_column1_success_column_title', 'Challenge'),
(12462, 719, '_story_columns_story_column1_success_column_title', 'field_6a3409fb6a21a'),
(12463, 719, 'story_columns_story_column1_success_column_paragraph', 'Waste, lighting and field services ran across disconnected systems no real-time visibility, no proof of performance.'),
(12464, 719, '_story_columns_story_column1_success_column_paragraph', 'field_6a340a286a21b'),
(12465, 719, 'story_columns_story_column1', ''),
(12466, 719, '_story_columns_story_column1', 'field_6a3409e56a219'),
(12467, 719, 'story_columns_story_column2_success_column_title', 'Solution'),
(12468, 719, '_story_columns_story_column2_success_column_title', 'field_6a340a5a6a21d'),
(12469, 719, 'story_columns_story_column2_success_column_paragraph', 'Caguar, LightSense, Visual and Discretal unified under one City Operations Center, operated 24/7 by LeSys.'),
(12470, 719, '_story_columns_story_column2_success_column_paragraph', 'field_6a340a5a6a21e'),
(12471, 719, 'story_columns_story_column2', ''),
(12472, 719, '_story_columns_story_column2', 'field_6a340a5a6a21c'),
(12473, 719, 'story_columns_story_column3_success_column_title', 'Result'),
(12474, 719, '_story_columns_story_column3_success_column_title', 'field_6a340a626a220'),
(12475, 719, 'story_columns_story_column3_success_column_paragraph', '70% energy saved, 18% lower fleet fuel, 25% fewer missed collections and sub-5-second SOS response.'),
