(12750, 752, '_hero_section', 'field_service_hero'),
(12751, 752, 'overview', 'Digital transformation is no longer limited to technology modernization—it is a strategic business initiative that reshapes how organizations operate, deliver services, engage stakeholders, and achieve long-term objectives.\r\n\r\nLESYS helps government entities, municipalities, utilities, and enterprises navigate complex transformation journeys by developing practical, measurable, and sustainable digital strategies that align technology investments with organizational priorities.'),
(12752, 752, '_overview', 'field_service_overview'),
(12753, 752, 'how_we_help', '<ul>\r\n 	<li>Enterprise-wide digital transformation strategies</li>\r\n 	<li>Digital maturity and readiness assessments</li>\r\n 	<li>Business process transformation initiatives</li>\r\n 	<li>Digital operating model design</li>\r\n 	<li>Digital governance and policy frameworks</li>\r\n 	<li>Transformation roadmaps and implementation plans</li>\r\n 	<li>Change management and adoption strategies</li>\r\n 	<li>KPI and performance measurement frameworks</li>\r\n</ul>'),
(12754, 752, '_how_we_help', 'field_service_delivery'),
(12755, 752, 'key_outcomes', '<ul>\r\n 	<li>Current-state operational and technology assessments</li>\r\n 	<li>Future-state digital vision development</li>\r\n 	<li>Transformation program governance</li>\r\n 	<li>Process optimization and automation planning</li>\r\n 	<li>Stakeholder engagement and alignment</li>\r\n 	<li>Technology portfolio rationalization</li>\r\n 	<li>Data-driven transformation planning</li>\r\n</ul>'),
(12756, 752, '_key_outcomes', 'field_service_capabilities'),
(12757, 752, 'operational_impact', '<ul>\r\n 	<li>Accelerates organizational modernization initiatives</li>\r\n 	<li>Improves service delivery and customer experiences</li>\r\n 	<li>Enhances operational efficiency and productivity</li>\r\n 	<li>Reduces transformation risks through structured planning</li>\r\n 	<li>Creates measurable outcomes and sustainable growth</li>\r\n 	<li>Maximizes return on digital investments</li>\r\n</ul>'),
(12758, 752, '_operational_impact', 'field_service_value'),
(12759, 752, 'why_lesys', 'LESYS combines strategic consulting expertise with deep implementation experience, ensuring that transformation initiatives move beyond vision and strategy to deliver tangible operational and business outcomes.'),
