(12815, 753, 'overview', 'Developing a smart city requires a comprehensive approach that integrates technology, governance, infrastructure, sustainability, and citizen engagement. LESYS assists city leaders and municipal authorities in designing smart city ecosystems that leverage digital technologies, data intelligence, and operational excellence to create more efficient, sustainable, and livable urban environments.'),
(12816, 753, '_overview', 'field_service_overview'),
(12817, 753, 'how_we_help', '• Smart city strategy development\r\n• Urban digital transformation roadmaps\r\n• Integrated Command and Control Center (ICCC) planning\r\n• Smart mobility and transportation strategies\r\n• Smart infrastructure frameworks\r\n• Smart governance and digital service models\r\n• Urban resilience and sustainability initiatives\r\n• Data and analytics strategies for city operations'),
(12818, 753, '_how_we_help', 'field_service_delivery'),
(12819, 753, 'key_outcomes', '•	Smart city maturity assessments \r\n•	Urban technology planning \r\n•	Multi-agency coordination frameworks \r\n•	IoT ecosystem strategy and design \r\n•	Citizen-centric service design \r\n•	Digital infrastructure planning \r\n•	Smart operations center consulting \r\n'),
(12820, 753, '_key_outcomes', 'field_service_capabilities'),
(12821, 753, 'operational_impact', '•	Enhance operational efficiency across city services \r\n•	Improves citizen satisfaction and quality of life \r\n•	Enables data-driven urban planning \r\n•	Supports sustainability and environmental objectives \r\n•	Optimizes municipal resource allocation \r\n•	Strengthens urban resilience and preparedness \r\n'),
(12822, 753, '_operational_impact', 'field_service_value'),
(12823, 753, 'why_lesys', 'Our expertise in municipal operations, digital platforms, command centers, and smart technologies enables cities to transform ambitious visions into practical, scalable, and measurable initiatives.'),
(12824, 753, '_why_lesys', 'field_service_why'),
