(13539, 759, 'hero_section_subtitle', 'Smart Cities Advisory'),
(13540, 759, '_hero_section_subtitle', 'field_service_subtitle'),
(13541, 759, 'hero_section_short_description', 'Developing a smart city requires a comprehensive approach that integrates technology, governance, infrastructure, sustainability, and citizen engagement. '),
(13542, 759, '_hero_section_short_description', 'field_service_short_desc'),
(13543, 759, 'hero_section', ''),
(13544, 759, '_hero_section', 'field_service_hero'),
(13545, 759, 'overview', 'Developing a smart city requires a comprehensive approach that integrates technology, governance, infrastructure, sustainability, and citizen engagement. LESYS assists city leaders and municipal authorities in designing smart city ecosystems that leverage digital technologies, data intelligence, and operational excellence to create more efficient, sustainable, and livable urban environments.'),
(13546, 759, '_overview', 'field_service_overview'),
(13547, 759, 'how_we_help', '<ul>\r\n 	<li>Smart city strategy development</li>\r\n 	<li>Urban digital transformation roadmaps</li>\r\n 	<li>Integrated Command and Control Center (ICCC) planning</li>\r\n 	<li>Smart mobility and transportation strategies</li>\r\n 	<li>Smart infrastructure frameworks</li>\r\n 	<li>Smart governance and digital service models</li>\r\n 	<li>Urban resilience and sustainability initiatives</li>\r\n 	<li>Data and analytics strategies for city operation</li>\r\n</ul>'),
(13548, 759, '_how_we_help', 'field_service_delivery'),
(13549, 759, 'key_outcomes', '<ul>\r\n 	<li>Smart city maturity assessments</li>\r\n 	<li>Urban technology planning</li>\r\n 	<li>Multi-agency coordination frameworks</li>\r\n 	<li>IoT ecosystem strategy and design</li>\r\n 	<li>Citizen-centric service design</li>\r\n 	<li>Digital infrastructure planning</li>\r\n 	<li>Smart operations center consulting</li>\r\n</ul>'),
(13550, 759, '_key_outcomes', 'field_service_capabilities'),
(13551, 759, 'operational_impact', '<ul>\r\n 	<li>Enhance operational efficiency across city services</li>\r\n 	<li>Improves citizen satisfaction and quality of life</li>\r\n 	<li>Enables data-driven urban planning</li>\r\n 	<li>Supports sustainability and environmental objectives</li>\r\n 	<li>Optimizes municipal resource allocation</li>\r\n 	<li>Strengthens urban resilience and preparedness</li>\r\n</ul>'),
(13552, 759, '_operational_impact', 'field_service_value'),
(13553, 759, 'why_lesys', 'Our expertise in municipal operations, digital platforms, command centers, and smart technologies enables cities to transform ambitious visions into practical, scalable, and measurable initiatives.'),
(13554, 759, '_why_lesys', 'field_service_why'),
