(13572, 759, '_story_columns_story_column1_success_column_title', 'field_6a3409fb6a21a'),
(13573, 759, 'story_columns_story_column1_success_column_paragraph', 'Waste, lighting and field services ran across disconnected systems no real-time visibility, no proof of performance.'),
