(13578, 759, '_story_columns_story_column2_success_column_title', 'field_6a340a5a6a21d'),
(13579, 759, 'story_columns_story_column2_success_column_paragraph', 'Caguar, LightSense, Visual and Discretal unified under one City Operations Center, operated 24/7 by LeSys.'),
