(13735, 763, 'footnotes', ''),
(13737, 763, 'hero_section_background_image', '761'),
(13738, 763, '_hero_section_background_image', 'field_hero_bg'),
(13739, 763, 'hero_section_subtitle', 'Industry Solutions'),
(13740, 763, '_hero_section_subtitle', 'field_hero_subtitle'),
(13741, 763, 'hero_section_short_description', 'Government entities are under increasing pressure to deliver efficient, transparent, secure, and citizen-centric services while managing complex regulatory requirements and growing public expectations. '),
(13742, 763, '_hero_section_short_description', 'field_hero_short_desc'),
(13743, 763, 'hero_section_cta_button_1_text', 'Contact Us'),
(13744, 763, '_hero_section_cta_button_1_text', 'field_6a3bb103ad45d'),
(13745, 763, 'hero_section_cta_button_2_text', 'Explore Industries'),
(13746, 763, '_hero_section_cta_button_2_text', 'field_6a3bb17aad45f'),
(13747, 763, 'hero_section_cta_button_1_url', 'https://beta.lesys.com/industry/government-public-sector/#contact'),
(13748, 763, '_hero_section_cta_button_1_url', 'field_6a3bb12dad45e'),
(13749, 763, 'hero_section_cta_button_2_url', 'https://beta.lesys.com/industries'),
(13750, 763, '_hero_section_cta_button_2_url', 'field_6a3bb208b2a2d'),
(13751, 763, 'hero_section', ''),
(13752, 763, '_hero_section', 'field_hero_section'),
(13753, 763, 'overview', 'Government entities are under increasing pressure to deliver efficient, transparent, secure, and citizen-centric services while managing complex regulatory requirements and growing public expectations. LESYS helps government organizations modernize operations, accelerate digital transformation, improve service delivery, and enhance decision-making through integrated technology, operational excellence, and data-driven governance.'),
(13754, 763, '_overview', 'field_overview'),
(13755, 763, 'how_we_help', '•	Digital government transformation initiatives \r\n•	National and regional command center solutions \r\n•	Citizen service modernization \r\n•	Government cloud and infrastructure services \r\n•	Cybersecurity and digital resilience programs \r\n•	Data governance and analytics platforms \r\n•	Smart workforce and operational management \r\n•	Integrated digital service delivery platforms \r\n'),
(13756, 763, '_how_we_help', 'field_how_we_help'),
(13757, 763, 'key_outcomes', '•	Improved citizen experience and service accessibility \r\n•	Enhanced transparency and accountability \r\n•	Faster decision-making through real-time intelligence \r\n•	Increased operational efficiency across departments \r\n•	Stronger cybersecurity and compliance posture \r\n•	Better utilization of public resources \r\n'),
(13758, 763, '_key_outcomes', 'field_key_outcomes'),
(13759, 763, 'operational_impact', 'Government organizations gain a unified operational environment where services, data, processes, and stakeholders are connected. Decision-makers have access to real-time insights, operational visibility, and performance metrics that support more effective governance and policy execution.'),
(13760, 763, '_operational_impact', 'field_operational_impact'),
(13761, 763, 'why_lesys', 'We combine deep public-sector understanding with advanced technologies and operational expertise to help governments deliver measurable improvements in efficiency, service quality, and public trust.'),
(13762, 763, '_why_lesys', 'field_why_lesys'),
(13763, 763, 'sucess_heading', 'Customer Success Story'),
(13764, 763, '_sucess_heading', 'field_6a34092d6a214'),
(13765, 763, 'success_title1', 'Entire Cities, Operated From'),
(13766, 763, '_success_title1', 'field_6a3409786a215'),
(13767, 763, 'success_title2', 'a Single'),
(13768, 763, '_success_title2', 'field_6a34098e6a216'),
(13769, 763, 'success_title3', 'Command Center'),
(13770, 763, '_success_title3', 'field_6a3409a26a217'),
(13771, 763, 'story_columns_story_column1_success_column_title', 'Challenge'),
(13772, 763, '_story_columns_story_column1_success_column_title', 'field_6a3409fb6a21a'),
(13773, 763, 'story_columns_story_column1_success_column_paragraph', 'Waste, lighting and field services ran across disconnected systems no real-time visibility, no proof of performance.'),
(13774, 763, '_story_columns_story_column1_success_column_paragraph', 'field_6a340a286a21b'),
(13775, 763, 'story_columns_story_column1', ''),
(13776, 763, '_story_columns_story_column1', 'field_6a3409e56a219'),
(13777, 763, 'story_columns_story_column2_success_column_title', 'Solution'),
(13778, 763, '_story_columns_story_column2_success_column_title', 'field_6a340a5a6a21d'),
(13779, 763, 'story_columns_story_column2_success_column_paragraph', 'Caguar, LightSense, Visual and Discretal unified under one City Operations Center, operated 24/7 by LeSys.'),
(13780, 763, '_story_columns_story_column2_success_column_paragraph', 'field_6a340a5a6a21e'),
(13781, 763, 'story_columns_story_column2', ''),
(13782, 763, '_story_columns_story_column2', 'field_6a340a5a6a21c'),
(13783, 763, 'story_columns_story_column3_success_column_title', 'Result'),
(13784, 763, '_story_columns_story_column3_success_column_title', 'field_6a340a626a220'),
(13785, 763, 'story_columns_story_column3_success_column_paragraph', '70% energy saved, 18% lower fleet fuel, 25% fewer missed collections and sub-5-second SOS response.'),
(13786, 763, '_story_columns_story_column3_success_column_paragraph', 'field_6a340a626a221'),
