(13867, 766, 'hero_section_subtitle', 'Industry Solutions'),
(13868, 766, '_hero_section_subtitle', 'field_hero_subtitle'),
(13869, 766, 'hero_section_short_description', 'Government entities are under increasing pressure to deliver efficient, transparent, secure, and citizen-centric services while managing complex regulatory requirements and growing public expectations. '),
(13870, 766, '_hero_section_short_description', 'field_hero_short_desc'),
(13871, 766, 'hero_section_cta_button_1_text', 'Contact Us'),
(13872, 766, '_hero_section_cta_button_1_text', 'field_6a3bb103ad45d'),
(13873, 766, 'hero_section_cta_button_2_text', 'Explore Industries'),
(13874, 766, '_hero_section_cta_button_2_text', 'field_6a3bb17aad45f'),
(13875, 766, 'hero_section_cta_button_1_url', 'https://beta.lesys.com/industry/government-public-sector/#contact'),
(13876, 766, '_hero_section_cta_button_1_url', 'field_6a3bb12dad45e'),
(13877, 766, 'hero_section_cta_button_2_url', 'https://beta.lesys.com/industries'),
(13878, 766, '_hero_section_cta_button_2_url', 'field_6a3bb208b2a2d'),
(13879, 766, 'hero_section', ''),
(13880, 766, '_hero_section', 'field_hero_section'),
(13881, 766, 'overview', 'Government entities are under increasing pressure to deliver efficient, transparent, secure, and citizen-centric services while managing complex regulatory requirements and growing public expectations. LESYS helps government organizations modernize operations, accelerate digital transformation, improve service delivery, and enhance decision-making through integrated technology, operational excellence, and data-driven governance.'),
(13882, 766, '_overview', 'field_overview'),
(13883, 766, 'how_we_help', '•	Digital government transformation initiatives \r\n•	National and regional command center solutions \r\n•	Citizen service modernization \r\n•	Government cloud and infrastructure services \r\n•	Cybersecurity and digital resilience programs \r\n•	Data governance and analytics platforms \r\n•	Smart workforce and operational management \r\n•	Integrated digital service delivery platforms \r\n'),
(13884, 766, '_how_we_help', 'field_how_we_help'),
(13885, 766, 'key_outcomes', '•	Improved citizen experience and service accessibility \r\n•	Enhanced transparency and accountability \r\n•	Faster decision-making through real-time intelligence \r\n•	Increased operational efficiency across departments \r\n•	Stronger cybersecurity and compliance posture \r\n•	Better utilization of public resources \r\n'),
(13886, 766, '_key_outcomes', 'field_key_outcomes'),
(13887, 766, 'operational_impact', 'Government organizations gain a unified operational environment where services, data, processes, and stakeholders are connected. Decision-makers have access to real-time insights, operational visibility, and performance metrics that support more effective governance and policy execution.'),
(13888, 766, '_operational_impact', 'field_operational_impact'),
(13889, 766, 'why_lesys', 'We combine deep public-sector understanding with advanced technologies and operational expertise to help governments deliver measurable improvements in efficiency, service quality, and public trust.'),
(13890, 766, '_why_lesys', 'field_why_lesys'),
(13891, 766, 'sucess_heading', 'Customer Success Story'),
(13892, 766, '_sucess_heading', 'field_6a34092d6a214'),
(13893, 766, 'success_title1', 'Entire Cities, Operated From'),
(13894, 766, '_success_title1', 'field_6a3409786a215'),
