(13900, 766, '_story_columns_story_column1_success_column_title', 'field_6a3409fb6a21a'),
(13901, 766, 'story_columns_story_column1_success_column_paragraph', 'Waste, lighting and field services ran across disconnected systems no real-time visibility, no proof of performance.'),
