(13906, 766, '_story_columns_story_column2_success_column_title', 'field_6a340a5a6a21d'),
(13907, 766, 'story_columns_story_column2_success_column_paragraph', 'Caguar, LightSense, Visual and Discretal unified under one City Operations Center, operated 24/7 by LeSys.'),
(13908, 766, '_story_columns_story_column2_success_column_paragraph', 'field_6a340a5a6a21e'),
(13909, 766, 'story_columns_story_column2', ''),
