(15754, 776, 'platform_subtitle', 'Autonomous Incident Management Platform'),
(15755, 776, '_platform_subtitle', 'field_subtitle'),
(15756, 776, 'brochure_url', 'https://beta.lesys.com/wp-content/uploads/2026/06/Automax-Brochure-2026.pdf'),
(15757, 776, '_brochure_url', 'field_brochure_url'),
(15758, 776, 'benchmarks', '80% Reduction in Operational Fragmentation\r\n70% Faster Incident Detection\r\n95%+ SLA Compliance\r\n50% Improved Operational Efficiency'),
(15759, 776, '_benchmarks', 'field_benchmarks'),
(15760, 776, 'ideal_for', 'Municipalities, Smart Cities, Utilities, Operations Centers, Facility Management, Public Safety, and Large Enterprises.'),
(15761, 776, '_ideal_for', 'field_ideal_for'),
(15762, 776, 'benefits', 'Unified governance and operational control\r\nAutonomous monitoring and early incident detection\r\nStreamlined incident lifecycle from ingestion to closure\r\nComplete traceability through a single-pane-of-glass view\r\nCoordinated execution across multiple departments and stakeholders\r\nReduced SLA violations through automated alerts and escalations\r\n'),
(15763, 776, '_benefits', 'field_benefits'),
(15764, 776, 'capabilities', 'High-velocity incident detection pipeline\r\nAdministrative governance dashboard\r\nRole-Based Access Control (RBAC)\r\nVisual workflow designer with drag-and-drop functionality\r\nReal-time incident monitoring and criticality visualization\r\nAdvanced analytics and reporting\r\nMobile application with GPS-enabled incident capture\r\nCloud, on-premise, and hybrid deployment options\r\nEnterprise-grade security, SAML, OAuth 2.0, and encryption'),
(15765, 776, '_capabilities', 'field_capabilities'),
