(16047, 807, 'benefits', 'Elimination of routine HR bottlenecks\r\nFaster approval and service delivery cycles\r\nImproved workforce visibility and control\r\nEnhanced employee experience and engagement\r\nImproved payroll accuracy\r\nGreater HR operational efficiency\r\n'),
(16048, 807, '_benefits', 'field_benefits'),
(16049, 807, 'capabilities', 'Geo-fenced attendance and time tracking\r\nLeave and request management\r\nEmployee profile and document repository\r\nMulti-level approval workflows\r\nAutomated notifications and alerts\r\nReal-time HR analytics dashboards\r\nSecure cloud and hybrid deployment\r\nMulti-factor authentication and enterprise security controls\r\n'),
