(16090, 807, '_thumbnail_id', '809'),
(16091, 807, 'platform_more_details', '<h2>Workforce Empowerment. Anytime. Anywhere.</h2>\r\n\r\nFoxHR is a modern Employee Self-Service platform that enables organizations to digitize workforce interactions, streamline HR operations, and enhance employee engagement through mobile-first experience.\r\n<h3>One Platform. Three Stakeholders.</h3>\r\n<br/>\r\nEmployees gain direct access to HR services, managers receive real-time workforce visibility, and HR teams benefit from automated processes and actionable insights.'),
(16092, 807, '_platform_more_details', 'field_6a4196161cdd5'),
(16096, 807, '_acf_changed', '1'),
(16097, 807, 'more_details_highlight-title', 'Workforce Empowerment. Anytime. Anywhere.'),
(16098, 807, '_more_details_highlight-title', 'field_6a4196161cdd5'),
(16099, 807, 'more_details_card-title', 'One Platform. Three Stakeholders.'),
(16100, 807, '_more_details_card-title', 'field_6a419941a29f8'),
(16101, 807, 'more_details_p_1', 'FoxHR is a modern Employee Self-Service platform that enables organizations to digitize workforce interactions, streamline HR operations, and enhance employee engagement through a mobile-first experience.'),
(16102, 807, '_more_details_p_1', 'field_6a41998ea29f9'),
(16103, 807, 'more_details_p_2', 'Employees gain direct access to HR services, managers receive real-time workforce visibility, and HR teams benefit from automated processes and actionable insights.'),
(16104, 807, '_more_details_p_2', 'field_6a4199b9a29fa'),
(16105, 776, '_acf_changed', '1'),
(16106, 776, 'more_details_highlight-title', 'Autonomous Incident Management. Unified Visibility. Intelligent Response.'),
(16107, 776, '_more_details_highlight-title', 'field_6a4196161cdd5'),
(16108, 776, 'more_details_card-title', 'From Blind Spots to Total Visibility'),
(16109, 776, '_more_details_card-title', 'field_6a419941a29f8'),
(16110, 776, 'more_details_p_1', 'Modern organizations face increasing operational complexity, fragmented workflows, and delayed incident response caused by disconnected systems and manual processes. Automax IMS transforms incident management by providing a centralized platform that autonomously detects, orchestrates, tracks, and resolves operational incidents from a single source of truth.'),
(16111, 776, '_more_details_p_1', 'field_6a41998ea29f9'),
(16112, 776, 'more_details_p_2', 'Automax IMS serves as a centralized intelligence hub that enables organizations to monitor operational health in real time, automate incident lifecycles, and coordinate cross-functional teams with precision and accountability.'),
(16113, 776, '_more_details_p_2', 'field_6a4199b9a29fa'),
