(16393, 820, 'ideal_for', 'Government Services, Smart Cities, Municipalities, Customer Service Centers, Healthcare, Education, Utilities, Banking, and Enterprise Organizations.'),
(16394, 820, '_ideal_for', 'field_ideal_for'),
(16395, 820, 'benefits', 'No coding knowledge required \r\nAccelerates customer response times \r\nReduces operational costs and workload \r\nImprove customer satisfaction and engagement \r\nSupports multilingual interactions \r\nScales from small deployments to enterprise-wide operations \r\nIntegrates with existing business systems and workflows \r\nDelivers secure and compliant digital interactions \r\n'),
(16396, 820, '_benefits', 'field_benefits'),
(16397, 820, 'capabilities', 'Multi-channel deployment (Web, Mobile, WhatsApp, Enterprise Platforms) \r\nAI-powered conversational experiences \r\nRetrieval-Augmented Generation (RAG) \r\nNatural Language Processing (NLP) \r\nChatGPT and LLM integrations \r\nDocument intelligence for PDF, Word, and CSV files \r\nVoice-to-text and text-to-speech capabilities \r\nSurvey and feedback management \r\nAPI and database integration \r\nAutomated reporting and file distribution \r\nConversation analytics and performance monitoring \r\nUser authentication and access control \r\nWebhooks and extensible integrations \r\nMultilingual and RTL language support \r\nCustomizable conversational workflows and responses \r\n'),
(16398, 820, '_capabilities', 'field_capabilities'),
(16399, 820, 'more_details_highlight-title', 'AI-Powered Customer Conversations. Intelligent Automation. Exceptional Experiences.'),
(16400, 820, '_more_details_highlight-title', 'field_6a4196161cdd5'),
(16401, 820, 'more_details_card-title', 'One Platform. Unlimited Conversations.'),
(16402, 820, '_more_details_card-title', 'field_6a419941a29f8'),
(16403, 820, 'more_details_p_1', 'Organizations today must provide fast, personalized, and always-available support across multiple digital channels. LeChatbot transforms customer and employee interactions through intelligent conversational AI that automates responses, streamlines service delivery, and enhances engagement without increasing operational complexity.'),
(16404, 820, '_more_details_p_1', 'field_6a41998ea29f9'),
(16405, 820, 'more_details_p_2', 'Whether deployed on websites, mobile applications, WhatsApp, or enterprise platforms, LeChatbot provides a unified conversational experience powered by advanced artificial intelligence, natural language processing, and enterprise-grade integrations.'),
(16406, 820, '_more_details_p_2', 'field_6a4199b9a29fa'),
