(16724, 826, 'ideal_for', 'Smart Cities, Municipalities, Utilities, Environmental Agencies, Public Safety Organizations, and Critical Infrastructure Operators.\r\n'),
(16725, 826, '_ideal_for', 'field_ideal_for'),
(16726, 826, 'the_result', 'LeChatBot enables organizations to provide intelligent, scalable, and always-available digital assistance while reducing service costs and improving customer experiences.'),
(16727, 826, '_the_result', 'field_6a41a26d07fe2'),
(16728, 826, 'benefits', 'Improved urban situational awareness \r\nFaster emergency detection and response \r\nReduced infrastructure failures and service disruptions \r\nSmarter resource utilization in city operations \r\nEnhanced environmental monitoring and compliance \r\nUnified operational visibility across city systems \r\n'),
(16729, 826, '_benefits', 'field_benefits'),
(16730, 826, 'capabilities', 'LoRaWAN-based IoT sensor network management \r\nReal-time infrastructure monitoring and anomaly detection \r\nEnvironmental sensing for air quality, soil, and weather conditions \r\nSOS emergency alert terminals with geo-tagging \r\nGIS-based digital twin of urban environments \r\nAutomated actuator control for irrigation and utilities \r\nTime-series data management and analytics \r\nHybrid, on-premise, and air-gapped deployment options '),
(16731, 826, '_capabilities', 'field_capabilities'),
(16732, 826, 'more_details_highlight-title', 'Discretal IoT – Unified Urban Intelligence'),
(16733, 826, '_more_details_highlight-title', 'field_6a4196161cdd5'),
(16734, 826, 'more_details_card-title', 'One Platform. Three Stakeholders.'),
(16735, 826, '_more_details_card-title', 'field_6a419941a29f8'),
(16736, 826, 'more_details_p_1', 'Discretal IoT is a city-scale intelligence platform that unifies environmental monitoring, infrastructure integrity, and public safety into a single operational view. It leverages distributed IoT sensors, real-time data processing, and GIS-based visualization to give authorities continuous awareness of urban conditions and enable faster, more informed decision-making across critical services.'),
(16737, 826, '_more_details_p_1', 'field_6a41998ea29f9'),
(16738, 826, 'more_details_p_2', 'Employees gain direct access to HR services, managers receive real-time workforce visibility, and HR teams benefit from automated processes and actionable insights.'),
(16739, 826, '_more_details_p_2', 'field_6a4199b9a29fa'),
