(16914, 544, '_the_result', 'field_6a41a26d07fe2'),
(16915, 544, 'benefits', 'Optimized energy consumption and operational efficiency \r\nImproved reliability of lighting infrastructure \r\nReduced maintenance effort through predictive insights \r\nEnhanced public safety through adaptive illumination \r\nGreater visibility into asset performance \r\nStronger sustainability and ESG alignment \r\n'),
(16916, 544, '_benefits', 'field_benefits'),
(16917, 544, 'capabilities', 'Adaptive and automated lighting control \r\nIntegration with environmental and traffic data \r\nPredictive maintenance and fault detection \r\nGIS-based lighting infrastructure visualization \r\nRemote telemetry and asset health monitoring \r\nAutomated incident ticketing and dispatching \r\nWorkforce assignment based on location \r\nESG and energy performance reporting '),
(16918, 544, '_capabilities', 'field_capabilities'),
(16919, 544, 'more_details_highlight-title', 'LightSense – Smart Lighting Infrastructure'),
(16920, 544, '_more_details_highlight-title', 'field_6a4196161cdd5'),
(16921, 544, 'more_details_card-title', ''),
(16922, 544, '_more_details_card-title', 'field_6a419941a29f8'),
(16923, 544, 'more_details_p_1', 'LightSense transforms traditional street lighting into an intelligent, adaptive infrastructure system that responds dynamically to environmental conditions, traffic patterns, and operational demands. It provides full lifecycle visibility of lighting assets while enabling automation, predictive maintenance, and energy optimization across city networks.'),
