(17065, 542, 'benefits', 'Expanded urban coverage beyond manual inspection limits \r\nFaster detection of infrastructure and environmental issues \r\nMore consistent and objective reporting \r\nImproved operational responsiveness \r\nBetter urban asset visibility and mapping \r\nEnhanced enforcement and compliance monitoring'),
(17066, 542, '_benefits', 'field_benefits'),
(17067, 542, 'capabilities', 'Real-time video analytics using deep learning models \r\nDetection of urban distortions across multiple categories \r\nDrone and aerial surveillance integration \r\nAutomated incident creation and classification \r\nSeverity scoring and prioritization of findings \r\nANPR with multilingual license plate recognition \r\nGIS mapping of detected assets and issues \r\nMobile field inspection application with offline support '),
(17068, 542, '_capabilities', 'field_capabilities'),
(17069, 542, 'more_details_highlight-title', 'Visional – AI Video Analytics Platform'),
(17070, 542, '_more_details_highlight-title', 'field_6a4196161cdd5'),
(17071, 542, 'more_details_card-title', ''),
(17072, 542, '_more_details_card-title', 'field_6a419941a29f8'),
(17073, 542, 'more_details_p_1', 'Visional is an AI-driven video intelligence system designed to automate urban inspection and monitoring. It processes live video feeds, drone imagery, and field recordings to detect infrastructure issues, environmental violations, and urban distortions, converting visual data into actionable insights and automated incident workflows.'),
(17074, 542, '_more_details_p_1', 'field_6a41998ea29f9'),
