(17211, 541, 'benefits', 'Improved operational transparency and accountability \r\nReduced inefficiencies in fleet and waste operations \r\nBetter resource and route utilization \r\nEnhanced service reliability and consistency\r\nReduced operational disputes and manual verification needs \r\nStronger maintenance planning and asset longevity\r\n'),
(17212, 541, '_benefits', 'field_benefits'),
(17213, 541, 'capabilities', 'Real-time fleet tracking and monitoring \r\nRFID-based waste collection verification \r\nIntelligent route optimization and planning \r\nPredictive vehicle maintenance and diagnostics \r\nWorkforce tracking and attendance management \r\nGeofencing and operational heatmaps \r\nCentralized command and control dashboard \r\nDigital audit trails and compliance tracking '),
