(17356, 836, 'benefits', 'Strengthens physical security through intelligent surveillance capabilities \r\nEnables proactive threat detection and faster incident response \r\nImproves visibility across facilities, assets, and operational environments \r\nReduces manual monitoring effort through automated analytics \r\nEnhances access control and perimeter security management \r\nSupports evidence collection and forensic investigations \r\nSimplifies security operations through centralized management \r\nProvides secure remote access for monitoring from any location \r\nAdapts easily to evolving operational and security requirements \r\nDeliver a scalable foundation for enterprise and smart city security initiatives'),
(17357, 836, '_benefits', 'field_benefits'),
(17358, 836, 'capabilities', 'Centralized CCTV camera management and monitoring \r\nAutomatic network camera discovery and onboarding \r\nLive video streaming and remote surveillance access \r\nContinuous, event-based, and scheduled recording modes \r\nAI-powered motion detection and intelligent event recognition \r\nObject detection and automated scene analysis \r\nFacial recognition for identity verification and monitoring \r\nLicense plate recognition for vehicle tracking and access control \r\nDetection zones and exclusion masking configuration \r\nReal-time notifications through mobile and email channels \r\nMobile application for remote monitoring and management \r\nUser and role-based access management \r\nAudit trails and activity logging \r\nVideo recovery and archival management \r\nCloud storage integration and backup capabilities \r\nMulti-language support including Arabic and English \r\nScalable architecture supporting small to enterprise-wide deployments '),
(17359, 836, '_capabilities', 'field_capabilities'),
(17360, 836, 'more_details_highlight-title', 'Unicam – Intelligent CCTV & Video Surveillance Platform'),
(17361, 836, '_more_details_highlight-title', 'field_6a4196161cdd5'),
(17362, 836, 'more_details_card-title', ''),
(17363, 836, '_more_details_card-title', 'field_6a419941a29f8'),
(17364, 836, 'more_details_p_1', 'Unicam is an advanced video surveillance and security management platform that combines live monitoring, intelligent recording, video analytics, facial recognition, license plate recognition, and real-time alerting into a single unified security ecosystem. Designed for government facilities, commercial enterprises, critical infrastructure, residential communities, and smart city environments, Unicam transforms traditional CCTV systems into proactive security platforms capable of detecting, analyzing, and responding to events as they occur.\r\nBuilt for continuous operations and large-scale deployments, Unicam enables organizations to centralize surveillance management, automate threat detection, and improve situational awareness across multiple locations. Through intelligent analytics, remote accessibility, and scalable architecture, the platform helps security teams move from passive monitoring to proactive incident prevention while maintaining complete visibility over assets, facilities, and operational environments.'),
(17365, 836, '_more_details_p_1', 'field_6a41998ea29f9'),
(17366, 836, 'more_details_p_2', ''),
(17367, 836, '_more_details_p_2', 'field_6a4199b9a29fa'),
