(17536, 837, 'the_result', ''),
(17537, 837, '_the_result', 'field_6a41a26d07fe2'),
(17538, 837, 'benefits', 'Full organizational control over identity data and authentication flows \r\nStrong alignment with regulatory, compliance, and sovereignty requirements \r\nReduced dependency on third-party identity providers \r\nImproved user experience through unified login and SSO \r\nEnhanced security through layered authentication mechanisms \r\nLower risk of credential leakage and unauthorized access \r\nSimplified access management across complex IT environments \r\nImproved operational resilience through self-hosted architecture \r\nFaster onboarding and reduced authentication friction for users \r\nBetter visibility and auditability of all identity-related activities '),
(17539, 837, '_benefits', 'field_benefits'),
(17540, 837, 'capabilities', 'Multi-factor authentication (TOTP, WebAuthn, biometrics, hardware keys) \r\nSingle Sign-On (SSO) across enterprise and legacy systems \r\nIdentity federation (SAML, OAuth2, OIDC integration) \r\nLDAP, Active Directory, and cloud directory integration \r\nRole-based and attribute-based access control policies \r\nSecure application proxy for protected internal applications \r\nMobile authentication vault with biometric locking \r\nOffline OTP generation and secure credential access \r\nQR-based onboarding and user provisioning \r\nCentralized identity directory and account management \r\nAudit logging for authentication events and policy enforcement \r\nContainerized deployment with Kubernetes support '),
(17541, 837, '_capabilities', 'field_capabilities'),
(17542, 837, 'more_details_highlight-title', 'LeAuth – Next-Gen Identity & Authentication Platform'),
(17543, 837, '_more_details_highlight-title', 'field_6a4196161cdd5'),
(17544, 837, 'more_details_card-title', ''),
(17545, 837, '_more_details_card-title', 'field_6a419941a29f8'),
(17546, 837, 'more_details_p_1', 'LeAuth is a self-hosted, enterprise identity and authentication platform designed to give organizations full sovereignty over digital identities while delivering seamless, modern authentication experiences across systems, applications, and devices. It consolidates authentication, multi-factor security, identity federation, and access governance into a unified control layer that can operate fully on-premise or in hybrid environments.'),
(17547, 837, '_more_details_p_1', 'field_6a41998ea29f9'),
