(17720, 839, 'benefits', 'Unified communication replacing multiple disconnected tools \r\nFaster collaboration across teams and departments \r\nStronger data security and communication privacy \r\nImproved decision-making through real-time interaction \r\nSeamless hybrid and remote work enablement \r\nReduced operational complexity through centralized communication \r\nFull organizational control over communication infrastructure \r\nEnhanced compliance for regulated industries and government environments '),
(17721, 839, '_benefits', 'field_benefits'),
(17722, 839, 'capabilities', 'Real-time instant messaging with threaded conversations and group channels \r\nHigh-definition audio and video calling with screen sharing and participant controls \r\nScheduled and ad-hoc virtual meetings with recording and chat support \r\nOrganization-wide contact directory with live presence indicators \r\nCross-platform access (web, mobile, desktop applications) \r\nSecure file sharing embedded within conversations \r\nRole-based access control and admin governance tools \r\nEnterprise directory integration (Active Directory, LDAP) \r\nMeeting security controls with authentication and compliance logging \r\nIntegration with enterprise systems such as ERP and recruitment platforms '),
(17723, 839, '_capabilities', 'field_capabilities'),
(17724, 839, 'more_details_highlight-title', 'Axionic – Unified Team Communication'),
(17725, 839, '_more_details_highlight-title', 'field_6a4196161cdd5'),
(17726, 839, 'more_details_card-title', ''),
(17727, 839, '_more_details_card-title', 'field_6a419941a29f8'),
(17728, 839, 'more_details_p_1', 'Axionic is a self-hosted enterprise communication and collaboration platform that consolidates messaging, voice communication, video conferencing, meetings, presence management, and secure file sharing into a single unified digital workspace. It is designed to replace fragmented communication tools with one integrated environment that enhances organizational coordination while maintaining strict security, governance, and compliance standards. The platform is built for mission-critical environments where communication continuity, data privacy, and operational control are essential, and it can be deployed fully on-premise, in private cloud environments, or in hybrid architectures depending on organizational requirements.'),
(17729, 839, '_more_details_p_1', 'field_6a41998ea29f9'),
