(18753, 859, '_ab_hero_title', 'field_ab_hero_title'),
(18754, 859, 'ab_hero_desc', 'LESYS is a technology and operations company dedicated to helping governments, municipalities, utilities, enterprises, and critical industries navigate the complexities of the digital era. We combine strategic consulting, advanced technologies, managed services, and operational expertise to create intelligent, resilient, and future-ready organizations.'),
