(18757, 859, '_ab_val_1_title', 'f_ab_v1_t'),
(18758, 859, 'ab_val_1_desc', '“To lead the region in architecting intelligent, resilient, and interoperable digital systems that transform operations, strengthen institutional capability, and drive sustainable value creation. We enable organizations to achieve excellence through data-driven leadership, advanced technologies, and future-ready operating models.”'),
