(19848, 885, 'hero_section_short_description', 'Government entities are under increasing pressure to deliver efficient, transparent, secure, and citizen-centric services while managing complex regulatory requirements and growing public expectations. '),
(19849, 885, '_hero_section_short_description', 'field_hero_short_desc'),
(19850, 885, 'hero_section_cta_button_1_text', 'Contact Us'),
(19851, 885, '_hero_section_cta_button_1_text', 'field_6a3bb103ad45d'),
(19852, 885, 'hero_section_cta_button_2_text', 'Explore Industries'),
