(19854, 885, 'hero_section_cta_button_1_url', 'https://beta.lesys.com/industry/government-public-sector/#contact'),
(19855, 885, '_hero_section_cta_button_1_url', 'field_6a3bb12dad45e'),
(19856, 885, 'hero_section_cta_button_2_url', 'https://beta.lesys.com/industries'),
(19857, 885, '_hero_section_cta_button_2_url', 'field_6a3bb208b2a2d'),
(19858, 885, 'hero_section', ''),
(19859, 885, '_hero_section', 'field_hero_section'),
(19860, 885, 'overview', 'Government entities are under increasing pressure to deliver efficient, transparent, secure, and citizen-centric services while managing complex regulatory requirements and growing public expectations. LESYS helps government organizations modernize operations, accelerate digital transformation, improve service delivery, and enhance decision-making through integrated technology, operational excellence, and data-driven governance.'),
(19861, 885, '_overview', 'field_overview'),
(19862, 885, 'how_we_help', '•	Digital government transformation initiatives \r\n•	National and regional command center solutions \r\n•	Citizen service modernization \r\n•	Government cloud and infrastructure services \r\n•	Cybersecurity and digital resilience programs \r\n•	Data governance and analytics platforms \r\n•	Smart workforce and operational management \r\n•	Integrated digital service delivery platforms \r\n'),
(19863, 885, '_how_we_help', 'field_how_we_help'),
(19864, 885, 'key_outcomes', '•	Improved citizen experience and service accessibility \r\n•	Enhanced transparency and accountability \r\n•	Faster decision-making through real-time intelligence \r\n•	Increased operational efficiency across departments \r\n•	Stronger cybersecurity and compliance posture \r\n•	Better utilization of public resources \r\n'),
(19865, 885, '_key_outcomes', 'field_key_outcomes'),
(19866, 885, 'operational_impact', 'Government organizations gain a unified operational environment where services, data, processes, and stakeholders are connected. Decision-makers have access to real-time insights, operational visibility, and performance metrics that support more effective governance and policy execution.'),
(19867, 885, '_operational_impact', 'field_operational_impact'),
(19868, 885, 'why_lesys', 'We combine deep public-sector understanding with advanced technologies and operational expertise to help governments deliver measurable improvements in efficiency, service quality, and public trust.'),
(19869, 885, '_why_lesys', 'field_why_lesys'),
