(19986, 888, 'hero_section', ''),
(19987, 888, '_hero_section', 'field_hero_section'),
(19988, 888, 'overview', 'Municipalities are responsible for managing diverse city services, infrastructure, assets, field operations, and citizen interactions. LESYS enables municipalities to transition from fragmented operations to integrated smart city ecosystems that improve service quality, sustainability, and urban resilience.'),
(19989, 888, '_overview', 'field_overview'),
(19990, 888, 'how_we_help', '•	Smart city strategy and implementation \r\n•	City Operations Centers (COP) \r\n•	Smart cleaning and waste management operations \r\n•	Smart inspection and compliance programs \r\n•	Intelligent field workforce management \r\n•	Urban IoT and sensor integration \r\n•	Citizen engagement platforms \r\n•	Municipal performance management systems \r\n'),
(19991, 888, '_how_we_help', 'field_how_we_help'),
(19992, 888, 'key_outcomes', '•	Improved city-wide operational visibility \r\n•	Faster incident detection and response \r\n•	Enhanced citizen satisfaction \r\n•	Increased operational efficiency \r\n•	Better management of municipal assets and resources \r\n•	More sustainable urban operations \r\n'),
(19993, 888, '_key_outcomes', 'field_key_outcomes'),
(19994, 888, 'operational_impact', 'Municipal leaders gain a real-time operational view of city services, enabling proactive management of infrastructure, public spaces, utilities, inspections, and field operations. Service delivery becomes measurable, accountable, and data-driven.'),
(19995, 888, '_operational_impact', 'field_operational_impact'),
(19996, 888, 'why_lesys', 'Our combination of smart city technologies, municipal operations expertise, and integrated platforms enables cities to operate more efficiently while delivering better experiences for residents and visitors.'),
(19997, 888, '_why_lesys', 'field_why_lesys'),
