(20116, 891, 'overview', 'Utility providers must balance operational reliability, infrastructure performance, sustainability goals, and increasing service demands. LESYS helps utility organizations modernize operations through intelligent monitoring, automation, predictive maintenance, and integrated operational control.'),
(20117, 891, '_overview', 'field_overview'),
(20118, 891, 'how_we_help', '•	Utility operations centers \r\n•	Asset monitoring and management \r\n•	Predictive maintenance solutions \r\n•	IoT-enabled infrastructure monitoring \r\n•	Workforce and field operations management \r\n•	Data analytics and operational intelligence \r\n•	Infrastructure modernization programs \r\n•	Cybersecurity for critical infrastructure \r\n'),
(20119, 891, '_how_we_help', 'field_how_we_help'),
(20120, 891, 'key_outcomes', '•	Increased service reliability and uptime \r\n•	Improved asset performance and lifespan \r\n•	Reduced operational costs \r\n•	Faster fault detection and resolution \r\n•	Enhanced workforce productivity \r\n•	Greater operational resilience \r\n'),
(20121, 891, '_key_outcomes', 'field_key_outcomes'),
(20122, 891, 'operational_impact', 'Utilities gain greater visibility into network performance, infrastructure health, and operational risks. Teams can proactively manage assets, reduce outages, optimize maintenance activities, and improve service continuity.'),
(20123, 891, '_operational_impact', 'field_operational_impact'),
(20124, 891, 'why_lesys', 'We help utility providers transform critical infrastructure operations into intelligent, resilient, and highly efficient service environments.'),
