(20229, 893, '_hero_section_subtitle', 'field_hero_subtitle'),
(20230, 893, 'hero_section_short_description', 'Defense and security organizations operate in highly demanding environments where resilience, situational awareness, cybersecurity, and operational readiness are mission critical. '),
(20231, 893, '_hero_section_short_description', 'field_hero_short_desc'),
(20232, 893, 'hero_section_cta_button_1_text', 'Contact Us'),
(20233, 893, '_hero_section_cta_button_1_text', 'field_6a3bb103ad45d'),
(20234, 893, 'hero_section_cta_button_2_text', 'Explore Industries'),
(20235, 893, '_hero_section_cta_button_2_text', 'field_6a3bb17aad45f'),
(20236, 893, 'hero_section_cta_button_1_url', 'https://beta.lesys.com/industry/defense-security/#contact'),
(20237, 893, '_hero_section_cta_button_1_url', 'field_6a3bb12dad45e'),
(20238, 893, 'hero_section_cta_button_2_url', 'https://beta.lesys.com/industries'),
(20239, 893, '_hero_section_cta_button_2_url', 'field_6a3bb208b2a2d'),
(20240, 893, 'hero_section', ''),
(20241, 893, '_hero_section', 'field_hero_section'),
(20242, 893, 'overview', 'Defense and security organizations operate in highly demanding environments where resilience, situational awareness, cybersecurity, and operational readiness are mission critical. LESYS delivers secure, integrated, and intelligence-driven solutions that support operational effectiveness and national security objectives.'),
(20243, 893, '_overview', 'field_overview'),
(20244, 893, 'how_we_help', '•	Command and control solutions \r\n•	Situational awareness platforms \r\n•	Cybersecurity operations centers \r\n•	Secure communications infrastructure \r\n•	Operational intelligence systems \r\n•	Critical infrastructure protection \r\n•	Data integration and analytics \r\n•	Mission support technologies '),
(20245, 893, '_how_we_help', 'field_how_we_help'),
(20246, 893, 'key_outcomes', '•	Enhanced operational readiness \r\n•	Improved situational awareness \r\n•	Faster response and coordination \r\n•	Increased cybersecurity resilience \r\n•	Better information sharing \r\n•	Greater operational effectiveness \r\n•	Improve public safety and internal security\r\n•	Deliver faster, digital citizen services\r\n•	Strengthening law enforcement capabilities\r\n•	Enable real-time data sharing across agencies\r\n•	Reduce fraud in identity and civil services\r\n•	Enhance border control and immigration management'),
(20247, 893, '_key_outcomes', 'field_key_outcomes'),
(20248, 893, 'operational_impact', 'Organizations gain unified visibility across operations, assets, personnel, and security environments, enabling informed decisions and coordinated responses to evolve situations.'),
(20249, 893, '_operational_impact', 'field_operational_impact'),
(20250, 893, 'why_lesys', 'We combine advanced technologies, secure architectures, and operational expertise to support mission-critical defense and security operations.'),
(20251, 893, '_why_lesys', 'field_why_lesys'),
(20252, 893, 'sucess_heading', 'Customer Success Story'),
