(21001, 908, 'overview', 'Educational institutions are increasingly adopting digital technologies to enhance learning experiences, improve operational efficiency, and support institutional growth. LESYS helps educational organizations create connected, secure, and future-ready learning environments.'),
(21002, 908, '_overview', 'field_overview'),
(21003, 908, 'how_we_help', '•	Digital campus transformation \r\n•	Smart campus solutions \r\n•	Learning infrastructure modernization \r\n•	Cybersecurity and digital safety programs \r\n•	Cloud and collaboration platforms \r\n•	Campus operations management \r\n•	Data and performance analytics \r\n•	Student and stakeholder engagement solutions \r\n'),
(21004, 908, '_how_we_help', 'field_how_we_help'),
(21005, 908, 'key_outcomes', '•	Improved learning experiences \r\n•	Enhanced operational efficiency \r\n•	Increased digital adoption \r\n•	Better campus safety and security \r\n•	Improved resource management \r\n•	Greater institutional agility '),
(21006, 908, '_key_outcomes', 'field_key_outcomes'),
(21007, 908, 'operational_impact', 'Educational institutions gain integrated environments where technology, facilities, academic services, and operational processes work together to support students, faculty, and administrators.'),
(21008, 908, '_operational_impact', 'field_operational_impact'),
(21009, 908, 'why_lesys', 'Our solutions help educational organizations create innovative and sustainable environments that improve learning outcomes and operational performance.'),
