(21111, 759, '_wp_old_slug', 'smart-cities-advisory-2'),
(21112, 759, 'overview_part1', 'Developing a smart city requires a comprehensive approach that integrates technology, governance, infrastructure, sustainability, and citizen engagement. '),
(21113, 759, '_overview_part1', 'field_service_overview'),
(21114, 759, 'overview_heading', ''),
(21115, 759, '_overview_heading', 'field_6a4103f3b6d2c'),
(21116, 759, 'overview_part2', 'LESYS assists city leaders and municipal authorities in designing smart city ecosystems that leverage digital technologies, data intelligence, and operational excellence to create more efficient, sustainable, and livable urban environments.'),
(21117, 759, '_overview_part2', 'field_6a4103bcb96c5'),
(21241, 759, '_acf_changed', '1'),
