(21245, 913, 'hero_section_background_image', ''),
(21246, 913, '_hero_section_background_image', 'field_service_bg'),
(21247, 913, 'hero_section_subtitle', 'Cybersecurity Advisory'),
(21248, 913, '_hero_section_subtitle', 'field_service_subtitle'),
(21249, 913, 'hero_section_short_description', 'As cyber threats continue to evolve, organizations require a proactive and strategic approach to cybersecurity. '),
(21250, 913, '_hero_section_short_description', 'field_service_short_desc'),
(21251, 913, 'hero_section', ''),
(21252, 913, '_hero_section', 'field_service_hero'),
(21253, 913, 'overview_part1', 'As cyber threats continue to evolve, organizations require a proactive and strategic approach to cybersecurity. '),
(21254, 913, '_overview_part1', 'field_service_overview'),
(21255, 913, 'overview_heading', ''),
(21256, 913, '_overview_heading', 'field_6a4103f3b6d2c'),
(21257, 913, 'overview_part2', 'LESYS helps organizations strengthen their security posture through comprehensive cybersecurity advisory services that address governance, risk management, compliance, resilience, and operational security.'),
(21258, 913, '_overview_part2', 'field_6a4103bcb96c5'),
(21259, 913, 'how_we_help', '<ul>\r\n    <li>Cybersecurity strategy and roadmap development</li>\r\n    <li>Cyber risk and vulnerability assessments</li>\r\n    <li>Security governance frameworks</li>\r\n    <li>Compliance readiness programs</li>\r\n    <li>Security maturity assessments</li>\r\n    <li>Incident response and crisis management planning</li>\r\n    <li>Business continuity and disaster recovery advisory</li>\r\n    <li>Security awareness and organizational readiness programs</li>\r\n</ul>'),
(21260, 913, '_how_we_help', 'field_service_delivery'),
(21261, 913, 'key_outcomes', '<ul>\r\n    <li>Cybersecurity governance and policy development</li>\r\n    <li>Security architecture assessments</li>\r\n    <li>Risk identification and mitigation planning</li>\r\n    <li>Security controls evaluation</li>\r\n    <li>Regulatory and compliance alignment</li>\r\n    <li>Operational resilience planning</li>\r\n    <li>Security transformation programs</li>\r\n</ul>'),
(21262, 913, '_key_outcomes', 'field_service_capabilities'),
(21263, 913, 'operational_impact', '<ul>\r\n    <li>Reduces exposure to cyber threats and vulnerabilities</li>\r\n    <li>Strengthens regulatory compliance posture</li>\r\n    <li>Enhances organizational resilience and preparedness</li>\r\n    <li>Improves stakeholder confidence and trust</li>\r\n    <li>Protects critical systems, assets, and data</li>\r\n    <li>Supports secure digital transformation initiatives</li>\r\n</ul>'),
(21264, 913, '_operational_impact', 'field_service_value'),
(21265, 913, 'why_lesys', 'We approach cybersecurity as a business enabler, aligning security investments with operational objectives while ensuring organizations remain resilient against evolving threats.'),
(21266, 913, '_why_lesys', 'field_service_why'),
