(21348, 915, 'hero_section_subtitle', 'Technology Assessment & Strategy'),
(21349, 915, '_hero_section_subtitle', 'field_service_subtitle'),
(21350, 915, 'hero_section_short_description', 'Technology decisions significantly impact an organization\'s ability to innovate, scale, and compete. '),
(21351, 915, '_hero_section_short_description', 'field_service_short_desc'),
(21352, 915, 'hero_section', ''),
(21353, 915, '_hero_section', 'field_service_hero'),
(21354, 915, 'overview_part1', 'Technology decisions significantly impact an organization\'s ability to innovate, scale, and compete. '),
(21355, 915, '_overview_part1', 'field_service_overview'),
(21356, 915, 'overview_heading', ''),
(21357, 915, '_overview_heading', 'field_6a4103f3b6d2c'),
(21358, 915, 'overview_part2', 'LESYS provides independent assessments and strategic guidance to help organizations evaluate existing technology landscapes, identify opportunities, and develop future-ready technology strategies.'),
(21359, 915, '_overview_part2', 'field_6a4103bcb96c5'),
(21360, 915, 'how_we_help', '<ul>\r\n	<li>Enterprise technology assessments </li>\r\n\r\n	<li>Infrastructure and cloud readiness evaluations </li>\r\n\r\n	<li>Technology modernization strategies </li>\r\n\r\n	<li>IT investment planning </li>\r\n\r\n	<li>Vendor and platform evaluations </li>\r\n\r\n	<li>Technology governance frameworks </li>\r\n\r\n	<li>Enterprise architecture reviews </li>\r\n\r\n	<li>Strategic technology roadmaps </li>\r\n</ul>\r\n\r\n'),
(21361, 915, '_how_we_help', 'field_service_delivery'),
(21362, 915, 'key_outcomes', '<ul>\r\n	<li>Technology audits and benchmarking</li>\r\n\r\n	<li>Gap and capability assessments</li>\r\n\r\n	<li>Application and infrastructure evaluations</li>\r\n\r\n	<li>Future-state architecture planning</li>\r\n\r\n	<li>Technology portfolio optimization</li>\r\n\r\n	<li>Digital capability planning</li>\r\n\r\n	<li>Strategic investment analysis</li>\r\n</ul>\r\n\r\n'),
(21363, 915, '_key_outcomes', 'field_service_capabilities'),
(21364, 915, 'operational_impact', '<ul>\r\n	<li>Improve technology investment decisions </li>\r\n\r\n	<li>Reduces operational inefficiencies and technical debt </li>\r\n\r\n	<li>Supports long-term scalability and innovation </li>\r\n\r\n	<li>Enhance business and technology alignment </li>\r\n\r\n	<li>Optimizes infrastructure and application performance </li>\r\n\r\n	<li>Increases organizational agility</li>\r\n </ul>\r\n\r\n'),
(21365, 915, '_operational_impact', 'field_service_value'),
(21366, 915, 'why_lesys', 'Our technology consultants combine industry expertise with practical implementation knowledge to deliver actionable recommendations that support both immediate priorities and long-term objectives.'),
(21367, 915, '_why_lesys', 'field_service_why'),
