(21496, 920, 'key_outcomes', '<ul>\r\n	<li>Multi-level support structure </li>\r\n	<li>\r\nService desk management </li>\r\n\r\n	<li>Issue diagnosis and resolution </li>\r\n\r\n	<li>Knowledge management</li>\r\n \r\n	<li>Performance reporting </li>\r\n\r\n	<li>Continuous service improvement </li>\r\n</ul>\r\n\r\n'),
(21497, 920, '_key_outcomes', 'field_service_capabilities'),
(21498, 920, 'operational_impact', '<ul>\r\n	<li>Faster issue resolution</li>\r\n \r\n	<li>Reduced downtime </li>\r\n\r\n	<li>Improved user satisfaction </li>\r\n\r\n	<li>Increased operational continuity </li>\r\n\r\n	<li>Better technology adoption </li>\r\n</ul>\r\n\r\n'),
(21499, 920, '_operational_impact', 'field_service_value'),
