(21594, 921, 'key_outcomes', '<ul>\r\n    <li>Customized learning paths</li>\r\n    <li>Instructor-led training</li>\r\n    <li>Hands-on workshops</li>\r\n    <li>Digital learning programs</li>\r\n    <li>Competency assessments</li>\r\n    <li>Adoption support</li>\r\n</ul> '),
(21595, 921, '_key_outcomes', 'field_service_capabilities'),
(21596, 921, 'operational_impact', '<ul>\r\n<li>Increased user adoption </li>\r\n\r\n<li>Improved workforce competency </li>\r\n\r\n<li>Reduced operational errors </li>\r\n\r\n<li>Enhanced productivity </li>\r\n\r\n<li>Faster realization of business value</li>\r\n </ul>\r\n\r\n'),
(21597, 921, '_operational_impact', 'field_service_value'),
