(21688, 922, 'overview_part2', 'Our support framework ensures measurable service quality and accountability.'),
(21689, 922, '_overview_part2', 'field_6a4103bcb96c5'),
(21690, 922, 'how_we_help', '<ul>\r\n<li>Customized SLA frameworks </li>\r\n\r\n<li>Tiered support programs </li>\r\n\r\n<li>24/7 support options</li>\r\n \r\n<li>Dedicated service management</li>\r\n \r\n	<li>Performance monitoring and reporting </li>\r\n\r\n	<li>Continuous service improvement initiatives </li></ul>\r\n\r\n\r\n'),
(21691, 922, '_how_we_help', 'field_service_delivery'),
(21692, 922, 'key_outcomes', '<ul >\r\n    <li>Service governance</li>\r\n    <li>KPI and SLA management</li>\r\n    <li>Escalation frameworks</li>\r\n    <li>Operational reporting</li>\r\n    <li>Service reviews and optimization</li>\r\n    <li>Customer success management</li>\r\n</ul>'),
(21693, 922, '_key_outcomes', 'field_service_capabilities'),
(21694, 922, 'operational_impact', '<ul>\r\n    <li>Predictable service performance</li>\r\n    <li>Improved operational reliability</li>\r\n    <li>Enhanced accountability</li>\r\n    <li>Reduced business risk</li>\r\n    <li>Greater stakeholder confidence</li>\r\n</ul>'),
(21695, 922, '_operational_impact', 'field_service_value'),
