(21815, 926, 'how_we_help', '•	Cleaning operations management \r\n•	Workforce scheduling and deployment \r\n•	Digital inspection programs \r\n•	Asset and equipment monitoring \r\n•	SLA monitoring and reporting \r\n•	Operational performance analytics '),
(21816, 926, '_how_we_help', 'field_service_delivery'),
(21817, 926, 'key_outcomes', '•	Mobile workforce management \r\n•	Smart task allocation \r\n•	Real-time operational visibility \r\n•	Proof-of-service verification \r\n•	Performance dashboards \r\n•	Compliance monitoring '),
(21818, 926, '_key_outcomes', 'field_service_capabilities'),
(21819, 926, 'operational_impact', '•	Improved cleanliness standards \r\n•	Enhanced workforce productivity \r\n•	Reduced operational costs \r\n•	Increased service accountability \r\n•	Better citizen and customer satisfaction '),
(21820, 926, '_operational_impact', 'field_service_value'),
(21821, 926, 'why_lesys', 'Our digital operations platforms transform traditional cleaning services into measurable, data-driven operations.'),
