(21901, 927, 'hero_section_subtitle', 'Smart Waste Management Operations'),
(21902, 927, '_hero_section_subtitle', 'field_service_subtitle'),
(21903, 927, 'hero_section_short_description', 'LESYS enables municipalities and service providers to modernize waste collection and disposal operations through intelligent technologies, route optimization, asset tracking, and centralized operational control.'),
(21904, 927, '_hero_section_short_description', 'field_service_short_desc'),
(21905, 927, 'hero_section', ''),
(21906, 927, '_hero_section', 'field_service_hero'),
(21907, 927, 'overview_part1', ''),
