(21909, 927, 'overview_heading', ''),
(21910, 927, '_overview_heading', 'field_6a4103f3b6d2c'),
(21911, 927, 'overview_part2', 'LESYS enables municipalities and service providers to modernize waste collection and disposal operations through intelligent technologies, route optimization, asset tracking, and centralized operational control.'),
(21912, 927, '_overview_part2', 'field_6a4103bcb96c5'),
(21913, 927, 'how_we_help', '<ul >\r\n    <li>Waste collection operations management</li>\r\n    <li>Route optimization services</li>\r\n    <li>Fleet and asset monitoring</li>\r\n    <li>Smart bin integration</li>\r\n    <li>Operational performance reporting</li>\r\n    <li>Service compliance monitoring</li>\r\n</ul>'),
(21914, 927, '_how_we_help', 'field_service_delivery'),
(21915, 927, 'key_outcomes', '<ul>\r\n    <li>GIS-enabled operations</li>\r\n    <li>IoT sensor integration</li>\r\n    <li>Fleet management</li>\r\n    <li>Workforce coordination</li>\r\n    <li>Real-time operational visibility</li>\r\n    <li>Sustainability analytics</li>\r\n</ul>'),
(21916, 927, '_key_outcomes', 'field_service_capabilities'),
(21917, 927, 'operational_impact', '<ul>\r\n    <li>Increased collection efficiency</li>\r\n    <li>Reduced fuel and operational costs</li>\r\n    <li>Improved environmental sustainability</li>\r\n    <li>Enhanced service quality</li>\r\n    <li>Greater operational transparency</li>\r\n</ul>'),
(21918, 927, '_operational_impact', 'field_service_value'),
(21919, 927, 'why_lesys', 'We combine operational expertise and smart technologies to create efficient, sustainable waste management ecosystems.'),
