(22011, 928, 'how_we_help', '<ul >\r\n    <li>Cleaning operations management</li>\r\n    <li>Workforce scheduling and deployment</li>\r\n    <li>Digital inspection programs</li>\r\n    <li>Asset and equipment monitoring</li>\r\n    <li>SLA monitoring and reporting</li>\r\n    <li>Operational performance analytics</li>\r\n</ul>'),
(22012, 928, '_how_we_help', 'field_service_delivery'),
(22013, 928, 'key_outcomes', '<ul>\r\n    <li>Mobile workforce management</li>\r\n    <li>Smart task allocation</li>\r\n    <li>Real-time operational visibility</li>\r\n    <li>Proof-of-service verification</li>\r\n    <li>Performance dashboards</li>\r\n    <li>Compliance monitoring</li>\r\n</ul>'),
(22014, 928, '_key_outcomes', 'field_service_capabilities'),
(22015, 928, 'operational_impact', '<ul>\r\n    <li>Improved cleanliness standards</li>\r\n    <li>Enhanced workforce productivity</li>\r\n    <li>Reduced operational costs</li>\r\n    <li>Increased service accountability</li>\r\n    <li>Better citizen and customer satisfaction</li>\r\n</ul>'),
