(22209, 930, 'key_outcomes', '<ul>\r\n	<li>Unified operational visibility</li>\r\n\r\n	<li>Data fusion and analytics</li>\r\n\r\n	<li>Cross-domain monitoring</li>\r\n\r\n	<li>Event and incident coordination</li>\r\n\r\n	<li>Decision support systems</li>\r\n\r\n	<li>Command and control operations</li>\r\n</ul>\r\n\r\n'),
(22210, 930, '_key_outcomes', 'field_service_capabilities'),
(22211, 930, 'operational_impact', '<ul>\r\n	<li>Improved city-wide coordination</li>\r\n\r\n	<li>Faster incident response</li>\r\n\r\n	<li>Enhanced decision-making</li>\r\n\r\n	<li>Increased operational efficiency</li>\r\n\r\n	<li>Better resource allocation</li>\r\n</ul>\r\n\r\n'),
