(22832, 961, '_overview_heading', 'field_6a4103f3b6d2c'),
(22833, 961, 'overview_part2', '<strong>LESYS </strong>provides comprehensive Managed Infrastructure Services that ensure the continuous performance, availability, and optimization of servers, storage systems, networks, virtualization platforms, and data center environments. Our proactive approach enables organizations to focus on their core mission while we manage the complexity of their technology ecosystem.'),
(22834, 961, '_overview_part2', 'field_6a4103bcb96c5'),
(22835, 961, 'how_we_help', '<ul>\r\n    <li>End-to-end infrastructure management</li>\r\n    <li>Data center operations management</li>\r\n    <li>Server and storage administration</li>\r\n    <li>Network management and monitoring</li>\r\n    <li>Virtualization platform management</li>\r\n    <li>Infrastructure lifecycle management</li>\r\n    <li>Backup and recovery management</li>\r\n    <li>Infrastructure performance optimization</li>\r\n</ul>'),
(22836, 961, '_how_we_help', 'field_service_delivery'),
(22837, 961, 'key_outcomes', '<ul>\r\n    <li>24/7 infrastructure monitoring</li>\r\n    <li>Proactive maintenance and issue prevention</li>\r\n    <li>Capacity planning and forecasting</li>\r\n    <li>Configuration and asset management</li>\r\n    <li>High availability and resilience planning</li>\r\n    <li>Infrastructure health reporting</li>\r\n    <li>Vendor and warranty management</li>\r\n</ul>'),
(22838, 961, '_key_outcomes', 'field_service_capabilities'),
(22839, 961, 'operational_impact', '<ul>\r\n    <li>Increased infrastructure availability and reliability</li>\r\n    <li>Reduced operational and maintenance costs</li>\r\n    <li>Improved system performance and stability</li>\r\n    <li>Enhanced business continuity and resilience</li>\r\n    <li>Predictable operational expenditure</li>\r\n    <li>Reduced burden on internal IT teams</li>\r\n</ul>'),
(22840, 961, '_operational_impact', 'field_service_value'),
(22841, 961, 'why_lesys', 'Our infrastructure specialists combine operational expertise, advanced monitoring technologies, and proven service management practices to deliver secure, reliable, and scalable infrastructure environments.'),
