(23019, 966, 'operational_impact', '<ul>\r\n    <li>Improved customer satisfaction</li>\r\n    <li>Enhanced service quality</li>\r\n    <li>Increased operational efficiency</li>\r\n    <li>Better workforce productivity</li>\r\n    <li>Reduced response times</li>\r\n    <li>Improved service consistency</li>\r\n</ul>'),
(23020, 966, '_operational_impact', 'field_service_value'),
(23021, 966, 'why_lesys', 'We combine operational excellence, advanced technologies, and performance-driven management practices to create exceptional engagement experiences.'),
