(136, 1, '2026-06-18 12:55:27', '2026-06-18 12:55:27', '{\n    \"LeSys-theme::global_heading2_setting\": {\n        \"value\": \"Experts. \",\n        \"type\": \"theme_mod\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-06-18 12:55:27\"\n    },\n    \"LeSys-theme::global_paragraph_setting\": {\n        \"value\": \"Every request routes to a dedicated solution owner. You\'ll get a tailored walkthrough, a solution brief and a booking link \\u2014 within one business day. \",\n        \"type\": \"theme_mod\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-06-18 12:55:27\"\n    },\n    \"LeSys-theme::feature_1_icon\": {\n        \"value\": \"<i class=\\\"fa-solid fa-check\\\"></i> \",\n        \"type\": \"theme_mod\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-06-18 12:55:27\"\n    },\n    \"LeSys-theme::feature_1_title\": {\n        \"value\": \"Mapped to your goal \",\n        \"type\": \"theme_mod\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-06-18 12:55:27\"\n    },\n    \"LeSys-theme::feature_1_desc\": {\n        \"value\": \"We map your challenge to the exact platforms before we meet. \",\n        \"type\": \"theme_mod\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-06-18 12:55:27\"\n    },\n    \"LeSys-theme::feature_2_icon\": {\n        \"value\": \"<i class=\\\"fa-regular fa-calendar\\\"></i> \",\n        \"type\": \"theme_mod\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-06-18 12:55:27\"\n    },\n    \"LeSys-theme::feature_2_title\": {\n        \"value\": \"Calendar booking included \",\n        \"type\": \"theme_mod\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-06-18 12:55:27\"\n    },\n    \"LeSys-theme::feature_2_desc\": {\n        \"value\": \"Pick a time on the confirmation page \\u2014 no back-and-forth. \",\n        \"type\": \"theme_mod\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-06-18 12:55: