(140, 1, '2026-06-18 13:20:06', '2026-06-18 13:20:06', '<div class=\"fnote\">Fields marked <span class=\"req\">*</span> are required.</div>\r\n\r\n<div class=\"frow\">\r\n  <div class=\"field\">\r\n    <label>FULL NAME <span class=\"req\">*</span></label>\r\n    [text* name placeholder \"Your name\"]\r\n  </div>\r\n  <div class=\"field\">\r\n    <label>WORK EMAIL <span class=\"req\">*</span></label>\r\n    [email* email placeholder \"you@organization.gov.sa\"]\r\n  </div>\r\n</div>\r\n\r\n<div class=\"frow\">\r\n  <div class=\"field\">\r\n    <label>ORGANIZATION <span class=\"req\">*</span></label>\r\n    [text* org placeholder \"Entity / company\"]\r\n  </div>\r\n  <div class=\"field\">\r\n    <label>JOB TITLE <span class=\"req\">*</span></label>\r\n    [text* title placeholder \"Your role\"]\r\n  </div>\r\n</div>\r\n\r\n<div class=\"frow\">\r\n  <div class=\"field\">\r\n    <label>AREA OF INTEREST <span class=\"req\">*</span></label>\r\n    [select* area include_blank \"Enterprise Modernization\" \"Smart City Operations\" \"AI & Automation\" \"Cybersecurity\" \"Managed Services\"]\r\n  </div>\r\n  <div class=\"field\">\r\n    <label>PHONE NUMBER <span class=\"req\">*</span></label>\r\n    [tel* phone placeholder \"+966 …\"]\r\n  </div>\r\n</div>\r\n\r\n<div class=\"frow\">\r\n  <div class=\"field ffull\">\r\n    <label>BUSINESS CHALLENGE (OPTIONAL)</label>\r\n    [textarea message placeholder \"What outcome are you driving toward?\"]\r\n  </div>\r\n</div>\r\n\r\n[submit class:fsubmit \"Talk to an expert →\"]\r\n\r\n<div class=\"fbot\">You\'ll be assigned a solution owner who reaches out within one business day.</div>\n1\n[_site_title] \"[your-subject]\"\n[_site_title] <r.amira@leadergroup.com>\n[_site_admin_email]\nFrom: [your-name] [your-email]\r\nSubject: [your-subject]\r\n\r\nMessage Body:\r\n[your-message]\r\n\r\n-- \r\nThis is a notification that a contact form was submitted on your website ([_site_title] [_site_url]).\nReply-To: [your-email]\n\n1\n1\n\n[_site_title] \"[your-subject]\"\n[_site_title] <r.amira@leadergroup.com>\n[your-email]\nMessage Body:\r\n[your-message]\r\n\r\n-- \r\nThis email is a receipt for your contact form submission on our website ([_site_title] [_site_url]) in which your email address was used. If that was not you, please ignore this message.\nReply-To: [_site_admin_email]\n\n1\n1\nThank you. A solution owner will reach out within one business day.\nThere was an error trying to send your message. Please try again later.\nOne or more fields have an error. Please check and try again.\nThere was an error trying to send your message. Please try again later.\nYou must accept the terms and conditions before sending your message.\nPlease fill out this field.\nThis field has a too long input.\nThis field has a too short input.\nThere was an unknown error uploading the file.\nYou are not allowed to upload files of this type.\nThe uploaded file is too large.\nThere was an error uploading the file.\nPlease enter a date in YYYY-MM-DD format.\nThis field has a too early date.\nThis field has a too late date.\nPlease enter a number.\nThis field has a too small number.\nThis field has a too large number.\nThe answer to the quiz is incorrect.\nPlease enter an email address.\nPlease enter a URL.\nPlease enter a telephone number.', 'Contact form 1', '', 'publish', 'closed', 'closed', '', 'contact-form-1', '', '', '2026-06-21 23:26:27', '2026-06-21 23:26:27', '', 0, 'https://beta.lesys.com/?post_type=wpcf7_contact_form&#038;p=140', 0, 'wpcf7_contact_form', '', 0),
