(678, 1, '2026-06-24 08:47:03', '2026-06-24 08:47:03', 'a:14:{s:10:\"aria-label\";s:0:\"\";s:4:\"type\";s:8:\"textarea\";s:12:\"instructions\";s:0:\"\";s:8:\"required\";b:0;s:17:\"conditional_logic\";b:0;s:7:\"wrapper\";a:3:{s:5:\"width\";s:0:\"\";s:5:\"class\";s:0:\"\";s:2:\"id\";s:0:\"\";}s:13:\"default_value\";s:416:\"<ul><li>Digital government transformation initiatives</li><li>National and regional command center solutions</li><li>Citizen service modernization</li><li>Government cloud and infrastructure services</li><li>Cybersecurity and digital resilience programs</li><li>Data governance and analytics platforms</li><li>Smart workforce and operational management</li><li>Integrated digital service delivery platforms</li></ul>\";s:4:\"tabs\";s:6:\"visual\";s:7:\"toolbar\";s:4:\"full\";s:12:\"media_upload\";i:0;s:9:\"new_lines\";s:0:\"\";s:9:\"maxlength\";s:0:\"\";s:11:\"placeholder\";s:0:\"\";s:4:\"rows\";s:0:\"\";}', 'How We Help', 'how_we_help', 'publish', 'closed', 'closed', '', 'field_how_we_help', '', '', '2026-06-24 09:00:43', '2026-06-24 09:00:43', '', 676, 'https://beta.lesys.com/?post_type=acf-field&#038;p=678', 2, 'acf-field', '', 0),
