(864, 1, '2026-06-29 01:59:20', '2026-06-29 01:59:20', 'a:11:{s:10:\"aria-label\";s:0:\"\";s:4:\"type\";s:8:\"textarea\";s:12:\"instructions\";s:0:\"\";s:8:\"required\";b:0;s:17:\"conditional_logic\";b:0;s:7:\"wrapper\";a:3:{s:5:\"width\";s:0:\"\";s:5:\"class\";s:0:\"\";s:2:\"id\";s:0:\"\";}s:13:\"default_value\";s:188:\"LESYS is a technology and operations company dedicated to helping governments, municipalities, utilities, enterprises, and critical industries navigate the complexities of the digital era.\";s:9:\"new_lines\";s:0:\"\";s:9:\"maxlength\";s:0:\"\";s:11:\"placeholder\";s:0:\"\";s:4:\"rows\";s:0:\"\";}', 'Hero Description', 'ab_hero_desc', 'publish', 'closed', 'closed', '', 'field_hero_desc', '', '', '2026-06-29 01:59:20', '2026-06-29 01:59:20', '', 861, 'https://beta.lesys.com/?post_type=acf-field&p=864', 2, 'acf-field', '', 0),
(865, 1, '2026-06-29 01:59:20', '2026-06-29 01:59:20', 'a:11:{s:10:\"aria-label\";s:0:\"\";s:4:\"type\";s:7:\"wysiwyg\";s:12:\"instructions\";s:0:\"\";s:8:\"required\";b:0;s:17:\"conditional_logic\";b:0;s:7:\"wrapper\";a:3:{s:5:\"width\";s:0:\"\";s:5:\"class\";s:0:\"\";s:2:\"id\";s:0:\"\";}s:13:\"default_value\";s:531:\"<p>Our approach extends beyond traditional technology implementation. We focus on enabling measurable business outcomes, operational efficiency, service excellence, and sustainable growth through integrated solutions that connect people, processes, technology, and data.</p><p>From digital transformation initiatives and smart city programs to cybersecurity, cloud modernization, municipal operations, and mission-critical command centers, LESYS serves as a trusted partner throughout every stage of the transformation journey.</p>\";s:4:\"tabs\";s:3:\"all\";s:7:\"toolbar\";s:4:\"full\";s:12:\"media_upload\";i:1;s:5:\"delay\";i:0;}', 'Narrative Content', 'ab_narrative', 'publish', 'closed', 'closed', '', 'field_narrative_text', '', '', '2026-06-29 01:59:20', '2026-06-29 01:59:20', '', 861, 'https://beta.lesys.com/?post_type=acf-field&p=865', 3, 'acf-field', '', 0),
(866, 1, '2026-06-29 01:59:20', '2026-06-29 01:59:20', 'a:11:{s:10:\"aria-label\";s:0:\"\";s:4:\"type\";s:8:\"textarea\";s:12:\"instructions\";s:0:\"\";s:8:\"required\";b:0;s:17:\"conditional_logic\";b:0;s:7:\"wrapper\";a:3:{s:5:\"width\";s:0:\"\";s:5:\"class\";s:0:\"\";s:2:\"id\";s:0:\"\";}s:13:\"default_value\";s:194:\"To lead the region in architecting intelligent, resilient, and interoperable digital systems that transform operations, strengthen institutional capability, and drive sustainable value creation.\";s:9:\"new_lines\";s:0:\"\";s:9:\"maxlength\";s:0:\"\";s:11:\"placeholder\";s:0:\"\";s:4:\"rows\";s:0:\"\";}', 'Vision Text', 'ab_vision', 'publish', 'closed', 'closed', '', 'field_vision_text', '', '', '2026-06-29 01:59:20', '2026-06-29 01:59:20', '', 861, 'https://beta.lesys.com/?post_type=acf-field&p=866', 4, 'acf-field', '', 0),
